type OperatorPayloadTruncation = {
  path: string;
  total_count: number;
  returned_count: number;
  next_offset: number;
};

const OPERATOR_PAYLOAD_PRIORITY_KEYS = [
  "ok",
  "error",
  "status",
  "brand_key",
  "selected_key",
  "proceeded",
  "proceed_confirmed",
  "account_data_loaded",
  "continuity_loaded",
  "continuation_choice_required",
  "continuation_choice",
  "continuity_state_expires_in_seconds",
  "account_execution_locked_until_growth_plan_approval",
  "continuity_capsule",
  "continuity_mode",
  "workflow_checkpoint",
  "growth_mission_brief",
  "account_execution",
  "calendar_coverage",
  "active_review_batch",
  "completed_review_batch",
  "unresolved_incidents",
  "required_recovery_actions",
  "new_scheduling_blocked",
  "current_engineering_continuation",
  "active_artifact_ids",
  "source_batch_progress",
  "next_call_requirement",
  "required_next_owner_action",
  "payload_contract",
] as const;
const OPERATOR_PAYLOAD_PRIORITY_RANK = new Map<string, number>(
  OPERATOR_PAYLOAD_PRIORITY_KEYS.map((key, index) => [key, index]),
);

function operatorPayloadBytes(value: unknown): number {
  return new TextEncoder().encode(JSON.stringify(value ?? null)).byteLength;
}

function compactOperatorPayloadValue(
  value: unknown,
  path: string,
  limits: { arrayItems: number; stringChars: number; objectKeys: number; maxDepth: number },
  truncations: OperatorPayloadTruncation[],
  depth = 0,
): unknown {
  if (value === null || value === undefined || typeof value === "number" || typeof value === "boolean") {
    return value ?? null;
  }
  if (typeof value === "string") {
    if (value.length <= limits.stringChars) return value;
    truncations.push({ path, total_count: value.length, returned_count: limits.stringChars, next_offset: limits.stringChars });
    return value.slice(0, limits.stringChars);
  }
  if (depth >= limits.maxDepth) {
    if (Array.isArray(value)) {
      truncations.push({ path, total_count: value.length, returned_count: 0, next_offset: 0 });
      return [];
    }
    return { compacted: true };
  }
  if (Array.isArray(value)) {
    const returned = value.slice(0, limits.arrayItems);
    if (value.length > returned.length) {
      truncations.push({ path, total_count: value.length, returned_count: returned.length, next_offset: returned.length });
    }
    return returned.map((entry, index) => compactOperatorPayloadValue(
      entry,
      `${path}[${index}]`,
      limits,
      truncations,
      depth + 1,
    ));
  }
  if (typeof value === "object") {
    const entries = Object.entries(value as Record<string, unknown>).map(([key, entry], index) => ({ key, entry, index }));
    const prioritizedEntries = [...entries].sort((left, right) => {
      const leftRank = OPERATOR_PAYLOAD_PRIORITY_RANK.get(left.key) ?? Number.MAX_SAFE_INTEGER;
      const rightRank = OPERATOR_PAYLOAD_PRIORITY_RANK.get(right.key) ?? Number.MAX_SAFE_INTEGER;
      return leftRank - rightRank || left.index - right.index;
    });
    const returnedEntries = prioritizedEntries.slice(0, limits.objectKeys);
    if (entries.length > returnedEntries.length) {
      truncations.push({ path, total_count: entries.length, returned_count: returnedEntries.length, next_offset: returnedEntries.length });
    }
    return Object.fromEntries(returnedEntries.map(({ key, entry }) => [
      key,
      compactOperatorPayloadValue(entry, path ? `${path}.${key}` : key, limits, truncations, depth + 1),
    ]));
  }
  return String(value).slice(0, limits.stringChars);
}

function compactOperatorContinuityReviewBatch(value: unknown): unknown {
  if (!value || typeof value !== "object" || Array.isArray(value)) return value ?? null;
  const batch = value as Record<string, unknown>;
  const rawItems = batch.items;
  const batchKeys = [
    "review_batch_id",
    "id",
    "brand_key",
    "workflow_session_id",
    "source_batch_id",
    "production_date",
    "timezone",
    "status",
    "item_count",
    "reused_existing",
    "source_batch_reused",
    "created_at",
    "updated_at",
  ];
  const compactedSummary = Object.fromEntries(batchKeys
    .filter((key) => Object.prototype.hasOwnProperty.call(batch, key))
    .map((key) => [key, batch[key]]));
  const itemKeys = [
    "review_item_id",
    "sequence",
    "draw_order",
    "source_batch_id",
    "source_selection_id",
    "source_identity_key",
    "source_type",
    "internal_source_id",
    "threads_post_id",
    "canonical_source_url",
    "source_text",
    "source_metrics",
    "source_card_id",
    "generation_run_id",
    "draft_id",
    "draft_status",
    "generated_post",
    "scheduled_post_id",
    "scheduled_time",
    "scheduled_status",
    "status",
    "showable",
  ];
  const items = Array.isArray(rawItems)
    ? rawItems.slice(0, MANIFEST_REVIEW_BATCH_SIZE).map((entry) => {
        if (!entry || typeof entry !== "object" || Array.isArray(entry)) return entry;
        const item = entry as Record<string, unknown>;
        return Object.fromEntries(itemKeys
          .filter((key) => Object.prototype.hasOwnProperty.call(item, key))
          .map((key) => [
            key,
            compactOperatorPayloadValue(
              item[key],
              `continuity_capsule.review_batch.items.${key}`,
              { arrayItems: 4, stringChars: 500, objectKeys: 24, maxDepth: 4 },
              [],
            ),
          ]));
      })
    : [];
  return { ...compactedSummary, items };
}

function compactOperatorContinuityCapsule(value: unknown): Record<string, unknown> | null {
  if (!value || typeof value !== "object" || Array.isArray(value)) return null;
  const capsule = value as Record<string, unknown>;
  const activeReviewBatch = capsule.active_review_batch;
  const completedReviewBatch = capsule.completed_review_batch;
  const unresolvedIncidents = capsule.unresolved_incidents;
  const requiredRecoveryActions = capsule.required_recovery_actions;
  const compactField = (
    key: string,
    fieldValue: unknown,
    limits: { arrayItems: number; stringChars: number; objectKeys: number; maxDepth: number },
  ) => compactOperatorPayloadValue(fieldValue, `continuity_capsule.${key}`, limits, []);
  const compactedSummary: Record<string, unknown> = {
    version: capsule.version ?? null,
    choice: capsule.choice ?? null,
    brand_key: capsule.brand_key ?? null,
    account_data_loaded: capsule.account_data_loaded ?? null,
    canonical_state_source: capsule.canonical_state_source ?? null,
    continuity_mode: capsule.continuity_mode ?? null,
    continuity_diagnostics: compactField("continuity_diagnostics", capsule.continuity_diagnostics, { arrayItems: 4, stringChars: 260, objectKeys: 24, maxDepth: 4 }),
    autonomy_governance: compactField("autonomy_governance", capsule.autonomy_governance, { arrayItems: 2, stringChars: 280, objectKeys: 24, maxDepth: 4 }),
    growth_mission_brief: compactField("growth_mission_brief", capsule.growth_mission_brief, { arrayItems: 3, stringChars: 320, objectKeys: 28, maxDepth: 5 }),
    account_execution: compactField("account_execution", capsule.account_execution, { arrayItems: 4, stringChars: 260, objectKeys: 24, maxDepth: 4 }),
    calendar_coverage: compactField("calendar_coverage", capsule.calendar_coverage, { arrayItems: 8, stringChars: 240, objectKeys: 32, maxDepth: 4 }),
    new_scheduling_blocked: capsule.new_scheduling_blocked ?? null,
    scheduling_block_reason: capsule.scheduling_block_reason ?? null,
    current_engineering_continuation: compactField("current_engineering_continuation", capsule.current_engineering_continuation, { arrayItems: 4, stringChars: 260, objectKeys: 24, maxDepth: 4 }),
    workflow_checkpoint: compactField("workflow_checkpoint", capsule.workflow_checkpoint, { arrayItems: 4, stringChars: 300, objectKeys: 24, maxDepth: 4 }),
    active_artifact_ids: compactField("active_artifact_ids", capsule.active_artifact_ids, { arrayItems: 4, stringChars: 240, objectKeys: 24, maxDepth: 4 }),
    source_batch_progress: compactField("source_batch_progress", capsule.source_batch_progress, { arrayItems: 4, stringChars: 240, objectKeys: 24, maxDepth: 4 }),
    next_artifact: compactField("next_artifact", capsule.next_artifact, { arrayItems: 4, stringChars: 320, objectKeys: 24, maxDepth: 4 }),
    current_source_card: compactField("current_source_card", capsule.current_source_card, { arrayItems: 2, stringChars: 240, objectKeys: 16, maxDepth: 3 }),
    current_draft: compactField("current_draft", capsule.current_draft, { arrayItems: 2, stringChars: 320, objectKeys: 16, maxDepth: 3 }),
    current_scheduled_post: compactField("current_scheduled_post", capsule.current_scheduled_post, { arrayItems: 2, stringChars: 240, objectKeys: 16, maxDepth: 3 }),
    idempotency: compactField("idempotency", capsule.idempotency, { arrayItems: 2, stringChars: 240, objectKeys: 16, maxDepth: 3 }),
    runtime_identity: compactField("runtime_identity", capsule.runtime_identity, { arrayItems: 2, stringChars: 240, objectKeys: 16, maxDepth: 3 }),
  };
  return {
    ...compactedSummary,
    active_review_batch: compactOperatorContinuityReviewBatch(activeReviewBatch),
    completed_review_batch: compactOperatorContinuityReviewBatch(completedReviewBatch),
    unresolved_incidents: compactOperatorPayloadValue(
      unresolvedIncidents ?? [],
      "continuity_capsule.unresolved_incidents",
      { arrayItems: 8, stringChars: 500, objectKeys: 32, maxDepth: 5 },
      [],
    ),
    required_recovery_actions: compactOperatorPayloadValue(
      requiredRecoveryActions ?? [],
      "continuity_capsule.required_recovery_actions",
      { arrayItems: 8, stringChars: 500, objectKeys: 32, maxDepth: 5 },
      [],
    ),
  };
}

function enforceOperatorPayloadBudget(payload: Record<string, unknown>): Record<string, unknown> {
  const originalBytes = operatorPayloadBytes(payload);
  if (originalBytes <= OPERATOR_MCP_MAX_STRUCTURED_BYTES) return payload;

  const continuityCapsule = payload.continuity_capsule;
  if (!continuityCapsule || typeof continuityCapsule !== "object" || Array.isArray(continuityCapsule)) {
    let arrayItems = 20;
    let stringChars = 1200;
    let objectKeys = 60;
    for (let attempt = 0; attempt < 6; attempt += 1) {
      const truncations: OperatorPayloadTruncation[] = [];
      const compacted = compactOperatorPayloadValue(
        payload,
        "",
        { arrayItems, stringChars, objectKeys, maxDepth: 5 },
        truncations,
      ) as Record<string, unknown>;
      const bounded = {
        ...compacted,
        payload_contract: {
          server_bounded: true,
          model_payload_sizing: false,
          byte_limit: OPERATOR_MCP_MAX_STRUCTURED_BYTES,
          original_bytes: originalBytes,
          returned_bytes: 0,
          truncated: true,
          truncated_paths: truncations.slice(0, 40),
        },
      };
      const contract = bounded.payload_contract as Record<string, unknown>;
      contract.returned_bytes = operatorPayloadBytes(bounded);
      if (Number(contract.returned_bytes) <= OPERATOR_MCP_MAX_STRUCTURED_BYTES) {
        return bounded;
      }
      arrayItems = Math.max(1, Math.floor(arrayItems / 2));
      stringChars = Math.max(160, Math.floor(stringChars / 2));
      objectKeys = Math.max(32, Math.floor(objectKeys / 2));
    }
  }


  if (continuityCapsule && typeof continuityCapsule === "object" && !Array.isArray(continuityCapsule)) {
    const criticalTopLevelKeys = [
      "ok",
      "error",
      "status",
      "brand_key",
      "selected_key",
      "proceeded",
      "proceed_confirmed",
      "account_data_loaded",
      "continuity_loaded",
      "continuation_choice_required",
      "continuation_choice",
      "continuity_state_expires_in_seconds",
      "continuity_capsule",
      "account_execution_locked_until_growth_plan_approval",
      "required_next_owner_action",
      "next_call_requirement",
      "operator_action_closure",
    ];
    const criticalPayload = Object.fromEntries(
      criticalTopLevelKeys
        .filter((key) => Object.prototype.hasOwnProperty.call(payload, key))
        .map((key) => [
          key,
          key === "continuity_capsule" ? compactOperatorContinuityCapsule(payload[key]) : payload[key],
        ]),
    );
    let criticalArrayItems = 8;
    let criticalStringChars = 600;
    for (let attempt = 0; attempt < 6; attempt += 1) {
      const truncations: OperatorPayloadTruncation[] = [];
      const compactedCritical = compactOperatorPayloadValue(
        criticalPayload,
        "",
        { arrayItems: criticalArrayItems, stringChars: criticalStringChars, objectKeys: 64, maxDepth: 7 },
        truncations,
      ) as Record<string, unknown>;
      const boundedCritical = {
        ...compactedCritical,
        payload_contract: {
          server_bounded: true,
          model_payload_sizing: false,
          byte_limit: OPERATOR_MCP_MAX_STRUCTURED_BYTES,
          original_bytes: originalBytes,
          returned_bytes: 0,
          truncated: true,
          continuity_receipt_preserved: true,
          fallback_summary: true,
          truncated_paths: truncations.slice(0, 40),
        },
      };
      const contract = boundedCritical.payload_contract as Record<string, unknown>;
      contract.returned_bytes = operatorPayloadBytes(boundedCritical);
      if (Number(contract.returned_bytes) <= OPERATOR_MCP_MAX_STRUCTURED_BYTES) {
        return boundedCritical;
      }
      criticalArrayItems = Math.max(MANIFEST_REVIEW_BATCH_SIZE, Math.floor(criticalArrayItems / 2));
      criticalStringChars = Math.max(120, Math.floor(criticalStringChars / 2));
    }
  }

  return {
    ok: payload.ok !== false,
    error: payload.error ?? null,
    status: payload.status ?? null,
        brand_key: payload.brand_key ?? null,
    continuity_capsule: continuityCapsule && typeof continuityCapsule === "object" && !Array.isArray(continuityCapsule)
      ? compactOperatorPayloadValue(compactOperatorContinuityCapsule(continuityCapsule), "continuity_capsule", { arrayItems: MANIFEST_REVIEW_BATCH_SIZE, stringChars: 120, objectKeys: 32, maxDepth: 6 }, [])
      : null,
    payload_contract: {
      server_bounded: true,
      model_payload_sizing: false,
      byte_limit: OPERATOR_MCP_MAX_STRUCTURED_BYTES,
      original_bytes: originalBytes,
      truncated: true,
      continuity_receipt_preserved: Boolean(continuityCapsule),
      fallback_summary: true,
      available_top_level_fields: Object.keys(payload).slice(0, 60),
    },
  };
}

function operatorClientSafeBrandKey(brandKey: GptBrandKey): string {
  if (brandKey === "manifest_mental") return "manifestmental";
  if (brandKey === "opmg_deadman") return "opmgdeadman";
  return brandKey;
}


