function normalizeGptStrategyToken(value: unknown, maxLength = 100): string | null {
  if (typeof value !== "string") {
    return null;
  }
  const normalized = value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_ -]+/g, "")
    .replace(/\s+/g, "_")
    .replace(/-+/g, "_")
    .replace(/_+/g, "_")
    .replace(/^_+|_+$/g, "");
  if (!normalized) {
    return null;
  }
  return normalized.length > maxLength ? normalized.slice(0, maxLength) : normalized;
}

function parseGptFieldsParam(value: string | null): Set<string> | null {
  if (!value?.trim()) {
    return null;
  }
  const fields = value
    .split(",")
    .map((field) => field.trim().toLowerCase())
    .filter(Boolean);
  return fields.length ? new Set(fields) : null;
}

function wantsGptField(fields: Set<string> | null, field: string): boolean {
  return fields === null || fields.has(field);
}

function parseBoundedIntegerParam(value: string | null, fallback: number, min: number, max: number): number {
  const parsed = Number(value ?? fallback);
  if (!Number.isFinite(parsed)) {
    return fallback;
  }
  return Math.min(Math.max(Math.trunc(parsed), min), max);
}

function normalizeGptPostStrategyInput(value: unknown): GptPostStrategyInput | null {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    return null;
  }
  const record = value as Record<string, unknown>;
  const strategy = {
    pillar: normalizeGptStrategyToken(record.pillar),
    hook_style: normalizeGptStrategyToken(record.hook_style),
    format: normalizeGptStrategyToken(record.format),
    intent: normalizeGptStrategyToken(record.intent),
    experiment: normalizeGptStrategyToken(record.experiment),
    novelty_level: normalizeGptStrategyToken(record.novelty_level),
    metadata_json: normalizeGptMemoryMetadata(record.metadata),
  };
  return Object.values(strategy).some((entry) => entry !== null) ? strategy : null;
}

function serializeGptPostStrategyTag(row: GptPostStrategyTagRow): {
  scheduled_post_id: number;
  account_id: string;
  threads_user_id: string;
  pillar: string | null;
  hook_style: string | null;
  format: string | null;
  intent: string | null;
  experiment: string | null;
  novelty_level: string | null;
  metadata: unknown;
  created_at: string;
  updated_at: string;
} {
  return {
    scheduled_post_id: Number(row.scheduled_post_id),
    account_id: row.account_id,
    threads_user_id: row.threads_user_id,
    pillar: row.pillar,
    hook_style: row.hook_style,
    format: row.format,
    intent: row.intent,
    experiment: row.experiment,
    novelty_level: row.novelty_level,
    metadata: row.metadata_json ? safeParseJsonString(row.metadata_json) ?? null : null,
    created_at: row.created_at,
    updated_at: row.updated_at,
  };
}

async function upsertGptPostStrategyTag(
  env: Env,
  input: {
    scheduledPostId: number;
    accountId: string;
    threadsUserId: string;
    strategy: GptPostStrategyInput | null;
  },
): Promise<void> {
  if (!input.strategy || !Number.isInteger(input.scheduledPostId) || input.scheduledPostId <= 0) {
    return;
  }
  await ensureGptPostStrategyTagsTable(env);
  await env.DB.prepare(
    `INSERT INTO gpt_post_strategy_tags (
      scheduled_post_id,
      account_id,
      threads_user_id,
      pillar,
      hook_style,
      format,
      intent,
      experiment,
      novelty_level,
      metadata_json
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(scheduled_post_id) DO UPDATE SET
      account_id = excluded.account_id,
      threads_user_id = excluded.threads_user_id,
      pillar = excluded.pillar,
      hook_style = excluded.hook_style,
      format = excluded.format,
      intent = excluded.intent,
      experiment = excluded.experiment,
      novelty_level = excluded.novelty_level,
      metadata_json = excluded.metadata_json`,
  )
    .bind(
      input.scheduledPostId,
      input.accountId,
      input.threadsUserId,
      input.strategy.pillar,
      input.strategy.hook_style,
      input.strategy.format,
      input.strategy.intent,
      input.strategy.experiment,
      input.strategy.novelty_level,
      input.strategy.metadata_json,
    )
    .run();
}

async function listGptPostStrategyTagsForScheduledPosts(
  env: Env,
  scheduledPostIds: number[],
): Promise<Map<number, ReturnType<typeof serializeGptPostStrategyTag>>> {
  const normalizedIds = Array.from(new Set(scheduledPostIds.filter((id) => Number.isInteger(id) && id > 0)));
  const result = new Map<number, ReturnType<typeof serializeGptPostStrategyTag>>();
  if (!normalizedIds.length || !(await doesTableExist(env, "gpt_post_strategy_tags"))) {
    return result;
  }
  const placeholders = normalizedIds.map(() => "?").join(", ");
  const rows = await env.DB.prepare(
    `SELECT scheduled_post_id, account_id, threads_user_id, pillar, hook_style, format, intent,
            experiment, novelty_level, metadata_json, created_at, updated_at
     FROM gpt_post_strategy_tags
     WHERE scheduled_post_id IN (${placeholders})`,
  )
    .bind(...normalizedIds)
    .all<GptPostStrategyTagRow>();
  for (const row of rows.results ?? []) {
    const serialized = serializeGptPostStrategyTag(row);
    result.set(serialized.scheduled_post_id, serialized);
  }
  return result;
}

async function listPostedGptStrategyTaggedPosts(
  env: Env,
  threadsUserId: string,
  limit = 100,
): Promise<GptTaggedPostedPost[]> {
  const normalizedLimit = Math.min(Math.max(Math.trunc(limit), 1), 250);
  const [scheduledExists, tagsExists, archiveExists] = await Promise.all([
    doesTableExist(env, "scheduled_posts"),
    doesTableExist(env, "gpt_post_strategy_tags"),
    doesTableExist(env, "threads_posts_archive"),
  ]);
  if (!scheduledExists || !tagsExists) {
    return [];
  }

  const archiveSelect = archiveExists
    ? `a.post_id,
       a.post_text AS archive_post_text,
       a.post_timestamp,
       a.post_permalink,
       a.post_username,
       a.profile_picture_url,
       a.views,
       a.likes,
       a.replies,
       a.reposts,
       a.quotes,
       a.shares,
       a.engagement_total`
    : `NULL AS post_id,
       NULL AS archive_post_text,
       NULL AS post_timestamp,
       NULL AS post_permalink,
       NULL AS post_username,
       NULL AS profile_picture_url,
       NULL AS views,
       NULL AS likes,
       NULL AS replies,
       NULL AS reposts,
       NULL AS quotes,
       NULL AS shares,
       NULL AS engagement_total`;
  const archiveJoin = archiveExists
    ? `LEFT JOIN threads_posts_archive a
         ON a.threads_user_id = s.threads_user_id
        AND a.post_id = s.published_post_id`
    : "";

  const rows = await env.DB.prepare(
    `SELECT
       s.id AS scheduled_post_id,
       s.post_text,
       s.status,
       s.scheduled_time,
       s.published_at,
       s.published_post_id,
       t.account_id,
       t.threads_user_id,
       t.pillar,
       t.hook_style,
       t.format,
       t.intent,
       t.experiment,
       t.novelty_level,
       t.metadata_json,
       t.created_at AS tag_created_at,
       t.updated_at AS tag_updated_at,
       ${archiveSelect}
     FROM scheduled_posts s
     INNER JOIN gpt_post_strategy_tags t
       ON t.scheduled_post_id = s.id
     ${archiveJoin}
     WHERE s.threads_user_id = ?
       AND s.status = ?
     ORDER BY COALESCE(s.published_at, s.scheduled_time) DESC, s.id DESC
     LIMIT ?`,
  )
    .bind(threadsUserId, SCHEDULED_POST_STATUS_POSTED, normalizedLimit)
    .all<{
      scheduled_post_id: number | string;
      post_text: string;
      status: string;
      scheduled_time: string;
      published_at: string | null;
      published_post_id: string | null;
      account_id: string;
      threads_user_id: string;
      pillar: string | null;
      hook_style: string | null;
      format: string | null;
      intent: string | null;
      experiment: string | null;
      novelty_level: string | null;
      metadata_json: string | null;
      tag_created_at: string;
      tag_updated_at: string;
      post_id: string | null;
      archive_post_text: string | null;
      post_timestamp: string | null;
      post_permalink: string | null;
      post_username: string | null;
      profile_picture_url: string | null;
      views: number | string | null;
      likes: number | string | null;
      replies: number | string | null;
      reposts: number | string | null;
      quotes: number | string | null;
      shares: number | string | null;
      engagement_total: number | string | null;
    }>();

  return (rows.results ?? []).map((row) => ({
    scheduled_post_id: Number(row.scheduled_post_id),
    published_post_id: row.published_post_id,
    text: row.post_text,
    status: row.status,
    scheduled_time_utc: row.scheduled_time,
    published_at: row.published_at,
    strategy: serializeGptPostStrategyTag({
      scheduled_post_id: row.scheduled_post_id,
      account_id: row.account_id,
      threads_user_id: row.threads_user_id,
      pillar: row.pillar,
      hook_style: row.hook_style,
      format: row.format,
      intent: row.intent,
      experiment: row.experiment,
      novelty_level: row.novelty_level,
      metadata_json: row.metadata_json,
      created_at: row.tag_created_at,
      updated_at: row.tag_updated_at,
    }),
    post: row.post_id
      ? {
        id: row.post_id,
        text: row.archive_post_text,
        timestamp: row.post_timestamp,
        permalink: row.post_permalink,
        username: row.post_username,
        profile_picture_url: row.profile_picture_url,
        views: Number(row.views ?? 0),
        likes: Number(row.likes ?? 0),
        replies: Number(row.replies ?? 0),
        reposts: Number(row.reposts ?? 0),
        quotes: Number(row.quotes ?? 0),
        shares: Number(row.shares ?? 0),
        engagement_total: Number(row.engagement_total ?? 0),
      }
      : null,
  }));
}

function calculateMedian(values: number[]): number {
  const sorted = values.filter((value) => Number.isFinite(value)).sort((left, right) => left - right);
  if (!sorted.length) {
    return 0;
  }
  const middle = Math.floor(sorted.length / 2);
  return sorted.length % 2 === 0
    ? (sorted[middle - 1] + sorted[middle]) / 2
    : sorted[middle];
}

function calculatePercentile(values: number[], percentile: number): number {
  const sorted = values.filter((value) => Number.isFinite(value)).sort((left, right) => left - right);
  if (!sorted.length) {
    return 0;
  }
  const index = Math.min(sorted.length - 1, Math.max(0, Math.ceil((percentile / 100) * sorted.length) - 1));
  return sorted[index];
}

function summarizeTagUsage(
  tags: Array<ReturnType<typeof serializeGptPostStrategyTag>>,
  field: "pillar" | "hook_style" | "format" | "intent" | "experiment" | "novelty_level",
): Array<{ key: string; used: number; fatigue_risk: "low" | "medium" | "high" }> {
  const counts = new Map<string, number>();
  for (const tag of tags) {
    const key = tag[field];
    if (!key) {
      continue;
    }
    counts.set(key, (counts.get(key) ?? 0) + 1);
  }
  return Array.from(counts.entries())
    .sort((left, right) => right[1] - left[1] || left[0].localeCompare(right[0]))
    .map(([key, used]) => ({
      key,
      used,
      fatigue_risk: used >= 5 ? "high" : used >= 3 ? "medium" : "low",
    }));
}

function summarizeTaggedPostPerformance(
  taggedPosts: GptTaggedPostedPost[],
  field: "pillar" | "hook_style" | "format" | "intent" | "experiment" | "novelty_level",
): Array<{
  key: string;
  posts: number;
  posts_with_metrics: number;
  median_engagement_total: number;
  median_likes: number;
    median_views: number;

}> {
  const grouped = new Map<string, GptTaggedPostedPost[]>();
  for (const taggedPost of taggedPosts) {
    const key = taggedPost.strategy[field];
    if (!key) {
      continue;
    }
    const posts = grouped.get(key) ?? [];
    posts.push(taggedPost);
    grouped.set(key, posts);
  }

  return Array.from(grouped.entries())
    .map(([key, posts]) => {
      const postsWithMetrics = posts.filter((post) => post.post !== null);
      return {
        key,
        posts: posts.length,
        posts_with_metrics: postsWithMetrics.length,
        median_engagement_total: Number(calculateMedian(postsWithMetrics.map((post) => post.post?.engagement_total ?? 0)).toFixed(2)),
        median_likes: Number(calculateMedian(postsWithMetrics.map((post) => post.post?.likes ?? 0)).toFixed(2)),
                median_views: Number(calculateMedian(postsWithMetrics.map((post) => post.post?.views ?? 0)).toFixed(2)),

      };
    })
    .sort((left, right) => right.posts_with_metrics - left.posts_with_metrics || right.median_engagement_total - left.median_engagement_total || left.key.localeCompare(right.key));
}

