function normalizePatternString(
  value: unknown,
  options: { maxLength?: number; allowEmpty?: boolean } = {},
): string | null {
  if (typeof value !== "string") {
    return null;
  }

  const trimmed = value.trim();
  if (!options.allowEmpty && !trimmed) {
    return null;
  }

  const maxLength = options.maxLength ?? 0;
  if (maxLength > 0 && trimmed.length > maxLength) {
    return trimmed.slice(0, maxLength);
  }

  return trimmed;
}

function normalizePatternMetric(value: unknown): number {
  const numericValue = Number(value ?? 0);
  if (!Number.isFinite(numericValue) || numericValue < 0) {
    return 0;
  }
  return Math.floor(numericValue);
}

function normalizePatternViews(value: unknown): number | null {
  const numericValue = Number(value);
  if (!Number.isFinite(numericValue) || numericValue < 0) {
    return null;
  }
  return Math.floor(numericValue);
}

function parsePublicThreadsViewCount(html: string): number | null {
  const match = html.match(/"view_counts"\s*:\s*(\d+)/);
  if (!match?.[1]) {
    return null;
  }
  const parsed = Number(match[1]);
  return Number.isFinite(parsed) && parsed >= 0 ? Math.floor(parsed) : null;
}

function decodeHtmlEntity(value: string): string {
  return value
    .replace(/&quot;/g, "\"")
    .replace(/&#34;/g, "\"")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">");
}

function parsePublicThreadsPostedAt(html: string): string | null {
  const patterns = [
    /"datePublished"\s*:\s*"([^"]+)"/,
    /"uploadDate"\s*:\s*"([^"]+)"/,
    /"published_time"\s*:\s*"([^"]+)"/,
    /<meta[^>]+(?:property|name)=["']article:published_time["'][^>]+content=["']([^"']+)["']/i,
    /<time[^>]+datetime=["']([^"']+)["']/i,
  ];

  for (const pattern of patterns) {
    const match = html.match(pattern);
    const rawValue = match?.[1] ? decodeHtmlEntity(match[1]) : null;
    const normalized = normalizePatternPostedAt(rawValue);
    if (normalized) {
      return normalized;
    }
  }

  return null;
}

async function fetchPublicThreadsMetadata(sourceUrl: string | null): Promise<{ views: number | null; postedAt: string | null }> {
  if (!sourceUrl || !/^https:\/\/(?:www\.)?threads\.com\//i.test(sourceUrl)) {
    return { views: null, postedAt: null };
  }
  try {
    const response = await fetch(sourceUrl, {
      headers: {
        "User-Agent": "Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) AppleWebKit/605.1.15 Version/17.0 Mobile/15E148 Safari/604.1",
      },
    });
    if (!response.ok) {
      return { views: null, postedAt: null };
    }
    const html = await response.text();
    return {
      views: parsePublicThreadsViewCount(html),
      postedAt: parsePublicThreadsPostedAt(html),
    };
  } catch {
    return { views: null, postedAt: null };
  }
}

function normalizePatternPostedAt(value: unknown): string | null {
  const normalized = normalizePatternString(value, { maxLength: 100 });
  if (!normalized) {
    return null;
  }
  const parsed = new Date(normalized);
  if (Number.isNaN(parsed.getTime())) {
    return null;
  }
  return parsed.toISOString();
}

function normalizePatternConfidence(value: unknown): "low" | "medium" | "high" {
  const normalized = normalizePatternString(value, { maxLength: 16 })?.toLowerCase();
  if (normalized === "low" || normalized === "high") {
    return normalized;
  }
  return "medium";
}

function normalizePatternRawPayload(value: unknown): string | null {
  if (value === undefined) {
    return null;
  }
  try {
    return JSON.stringify(value);
  } catch {
    return null;
  }
}

function derivePatternAuthorHandleFromSourceUrl(sourceUrl: string | null): string | null {
  if (!sourceUrl) {
    return null;
  }
  try {
    const parsed = new URL(sourceUrl);
    const match = parsed.pathname.match(/\/@([^/]+)/);
    return match?.[1]?.trim() || null;
  } catch {
    const match = sourceUrl.match(/\/@([^/?#]+)/);
    return match?.[1]?.trim() || null;
  }
}

function extractThreadsPostIdFromUrl(sourceUrl: string | null): string | null {
  if (!sourceUrl) {
    return null;
  }
  try {
    const parsed = new URL(sourceUrl);
    const match = parsed.pathname.match(/\/post\/([^/?#]+)/i);
    return match?.[1]?.trim() || null;
  } catch {
    const match = sourceUrl.match(/\/post\/([^/?#]+)/i);
    return match?.[1]?.trim() || null;
  }
}

function canonicalizeThreadsSourceUrl(sourceUrl: string | null): string | null {
  if (!sourceUrl) {
    return null;
  }
  try {
    const parsed = new URL(sourceUrl);
    const hostname = parsed.hostname.toLowerCase().replace(/^www\./, "");
    if (hostname === "threads.com" || hostname === "threads.net") {
      parsed.protocol = "https:";
      parsed.hostname = "www.threads.com";
    }
    parsed.hash = "";
    parsed.search = "";
    parsed.pathname = parsed.pathname.replace(/\/+$/, "") || "/";
    return parsed.toString().replace(/\/$/, "");
  } catch {
    return sourceUrl.trim().replace(/[?#].*$/, "").replace(/\/+$/, "") || null;
  }
}

function escapeRegExp(value: string): string {

  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function stripThreadsInlineUiTail(value: string): string {
  return value
    .replace(/\s*(?:Sort\s*)?Top\s*More\s*View activity.*$/i, "")
    .replace(/\s*View activity\s*View activity\s*Reply to .*/i, "")
    .replace(/\s*Reply to [^\n]*?(?:Attach media|Add a GIF|Expand composer).*$/i, "")
    .trim();
}

function sanitizeImportedPatternText(
  text: string | null,
  authorHandle: string | null,
  authorDisplayName: string | null,
): string | null {
  if (!text) {
    return null;
  }

  const normalizedHandle = authorHandle?.trim().replace(/^@/, "") ?? "";
  const normalizedName = authorDisplayName?.trim() ?? "";
  const dateMetadataPattern = /^(?:(?:jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:t(?:ember)?)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\s+\d{1,2},?\s+\d{4}|\d{1,2}\/\d{1,2}\/\d{2,4})(?:,?\s*(?:at\s*)?\d{1,2}:\d{2}\s*(?:am|pm)?)?$/i;
  const cleanedLines = text
    .split("\n")
    .map((line) => line.trim())
    .map((line) => {
      let next = stripThreadsInlineUiTail(line);
      if (normalizedHandle) {
        next = next.replace(new RegExp(`^@?${escapeRegExp(normalizedHandle)}\\s+`, "i"), "");
      }
      if (normalizedName) {
        next = next.replace(new RegExp(`^${escapeRegExp(normalizedName)}\\s+`, "i"), "");
      }
      next = next.replace(/^@?[a-z0-9._]{2,40}\s+\d+\s*(?:s|m|h|d|w|mo|y)\s+/i, "");
      next = next.replace(/^\d+\s*(?:seconds?|secs?|s|minutes?|mins?|m|hours?|hrs?|h|days?|d|weeks?|w|months?|mos?|mo|years?|yrs?|y)\s+/i, "");
      next = next.replace(/^\d+\s*(?:seconds?|secs?|s|minutes?|mins?|m|hours?|hrs?|h|days?|d|weeks?|w|months?|mos?|mo|years?|yrs?|y)\b\s*/i, "");
      next = next.replace(/^\/\s*\d+\s+/i, "");
      return next.trim();
    })
    .filter((line) => {
      if (!line) {
        return false;
      }
      const lower = line.toLowerCase();
      if (normalizedHandle && (lower === normalizedHandle.toLowerCase() || lower === `@${normalizedHandle.toLowerCase()}`)) {
        return false;
      }
      if (normalizedName && lower === normalizedName.toLowerCase()) {
        return false;
      }
      if (lower === "/" || lower === "thread") {
        return false;
      }
      if (lower.includes("view activity") || lower.includes("expand composer") || lower.includes("attach media") || lower.includes("add a gif")) {
        return false;
      }
      if (/^\d+\s*\/\s*\d+$/.test(lower) || /^\/\s*\d+$/.test(lower)) {
        return false;
      }
      if (/^\d{1,2}$/.test(lower)) {
        return false;
      }
      if (dateMetadataPattern.test(line)) {
        return false;
      }
      return true;
    });

  return cleanedLines.join("\n").trim() || null;
}

function sanitizeExternalPatternRow(row: ExternalPatternRow): ExternalPatternRow {
  const sourceAuthorHandle = derivePatternAuthorHandleFromSourceUrl(row.source_url);
  const sanitizedText = sanitizeImportedPatternText(
    row.post_text,
    sourceAuthorHandle ?? row.author_handle,
    row.author_display_name,
  );
  return {
    ...row,
    post_text: sanitizedText ?? row.post_text,
    author_handle: sourceAuthorHandle ?? row.author_handle,
  };
}

async function importExternalPattern(
  env: Env,
  appUserId: string,
  accountId: string,
  payload: Record<string, unknown>,
): Promise<ExternalPatternRow> {
  await ensureExternalPatternsTable(env);

    const platform = normalizePatternString(payload.platform, { maxLength: 40 }) ?? "threads";
  const rawSourceUrl = normalizePatternString(payload.source_url, { maxLength: 2000 });
  const suppliedPostId = normalizePatternString(payload.post_id, { maxLength: 255 });
  const postId = suppliedPostId ?? extractThreadsPostIdFromUrl(rawSourceUrl);
  const sourceUrl = canonicalizeThreadsSourceUrl(rawSourceUrl);
  const authorHandle = derivePatternAuthorHandleFromSourceUrl(rawSourceUrl)
    ?? normalizePatternString(payload.author_handle, { maxLength: 255 });
  const authorDisplayName = normalizePatternString(payload.author_display_name, { maxLength: 255 });
  const rawPostText = normalizePatternString(payload.post_text, { maxLength: 20000 });
  const postText = sanitizeImportedPatternText(rawPostText, authorHandle, authorDisplayName);
  const likes = normalizePatternMetric(payload.likes);
  const replies = normalizePatternMetric(payload.replies);
  const reposts = normalizePatternMetric(payload.reposts);
  const shares = normalizePatternMetric(payload.shares);
  const payloadViews = normalizePatternViews(payload.views);
  const payloadPostedAt = normalizePatternPostedAt(payload.posted_at);
  const needsPublicMetadata = (!payloadViews || payloadViews <= 0) || !payloadPostedAt;
  const publicMetadata = needsPublicMetadata
    ? await fetchPublicThreadsMetadata(sourceUrl)
    : { views: null, postedAt: null };
  const views = payloadViews && payloadViews > 0
    ? payloadViews
    : publicMetadata.views;
  const postedAt = payloadPostedAt ?? publicMetadata.postedAt;
  const captureConfidence = normalizePatternConfidence(payload.capture_confidence);
  const rawPayload = normalizePatternRawPayload(payload.raw_payload);

  if (!sourceUrl || !postText) {
    throw new Error("source_url and post_text are required");
  }

  const existing = postId
    ? await env.DB.prepare(
      `SELECT id
       FROM external_patterns
       WHERE app_user_id = ?
         AND account_id = ?
         AND platform = ?
         AND post_id = ?
       LIMIT 1`,
    ).bind(appUserId, accountId, platform, postId).first<{ id: number }>()
    : await env.DB.prepare(
      `SELECT id
       FROM external_patterns
       WHERE app_user_id = ?
         AND account_id = ?
         AND source_url = ?
       LIMIT 1`,
    ).bind(appUserId, accountId, sourceUrl).first<{ id: number }>();

  const nowIso = new Date().toISOString();
  let patternId = Number(existing?.id ?? 0);
  if (patternId) {
    await env.DB.prepare(
      `UPDATE external_patterns
       SET platform = ?,
           source_url = ?,
           post_id = ?,
           author_handle = ?,
           author_display_name = ?,
           post_text = ?,
           likes = ?,
           replies = ?,
           reposts = ?,
           shares = ?,
           views = ?,
           posted_at = ?,
           capture_confidence = ?,
           raw_payload = ?,
           updated_at = ?
       WHERE id = ?
         AND app_user_id = ?
         AND account_id = ?`,
    ).bind(
      platform,
      sourceUrl,
      postId,
      authorHandle,
      authorDisplayName,
      postText,
      likes,
      replies,
      reposts,
      shares,
      views,
      postedAt,
      captureConfidence,
      rawPayload,
      nowIso,
      patternId,
      appUserId,
      accountId,
    ).run();
  } else {
    const inserted = await env.DB.prepare(
      `INSERT INTO external_patterns (
        app_user_id, account_id, platform, source_url, post_id, author_handle, author_display_name,
        post_text, likes, replies, reposts, shares, views, posted_at, capture_confidence,
        raw_payload, saved_at, updated_at
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    ).bind(
      appUserId,
      accountId,
      platform,
      sourceUrl,
      postId,
      authorHandle,
      authorDisplayName,
      postText,
      likes,
      replies,
      reposts,
      shares,
      views,
      postedAt,
      captureConfidence,
      rawPayload,
      nowIso,
      nowIso,
    ).run();
    patternId = Number(inserted.meta?.last_row_id ?? 0);
  }

  const row = await env.DB.prepare(
    `SELECT id, app_user_id, platform, source_url, post_id, author_handle, author_display_name,
            account_id, post_text, likes, replies, reposts, shares, views, posted_at, capture_confidence,
            raw_payload, saved_at, updated_at
     FROM external_patterns
     WHERE id = ?
       AND app_user_id = ?
       AND account_id = ?
     LIMIT 1`,
  )
    .bind(patternId, appUserId, accountId)
    .first<ExternalPatternRow>();


  if (!row) {
    throw new Error("pattern_import_failed");
  }

  return row;
}

async function deleteExternalPatterns(
  env: Env,
  appUserId: string,
  accountId: string,
  ids: number[],
): Promise<number> {
  await ensureExternalPatternsTable(env);

  const normalizedIds = Array.from(
    new Set(
      ids
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0),
    ),
  );

  if (!normalizedIds.length) {
    return 0;
  }

  const placeholders = normalizedIds.map(() => "?").join(", ");
  const result = await env.DB.prepare(
    `DELETE FROM external_patterns
     WHERE app_user_id = ?
       AND account_id = ?
       AND id IN (${placeholders})`,
  )
    .bind(appUserId, accountId, ...normalizedIds)
    .run();

  return Number(result.meta.changes ?? 0);
}

async function resolvePatternAccountId(
  env: Env,
  threadsUserId: string | null,
  requestedAccountId?: string | null,
): Promise<string> {
  const normalizedAccountId = requestedAccountId?.trim().toLowerCase() ?? "";
  if (normalizedAccountId && CONFIGURED_THREADS_ACCOUNTS.some((account) => account.id === normalizedAccountId)) {
    return normalizedAccountId;
  }

  const normalizedThreadsUserId = threadsUserId?.trim() ?? "";
  if (!normalizedThreadsUserId) {
    return DEFAULT_PATTERNS_ACCOUNT_ID;
  }

  const profiles = await getConfiguredThreadsProfiles(env);
  return profiles.find((profile) => profile.threads_user_id === normalizedThreadsUserId)?.account_id
    ?? DEFAULT_PATTERNS_ACCOUNT_ID;
}

async function ensureAutomationDailyRunLocksTable(env: Env): Promise<void> {
  await env.DB.prepare(
    `CREATE TABLE IF NOT EXISTS automation_daily_run_locks (
      automation_id TEXT NOT NULL,
      account_id TEXT NOT NULL,
      run_date TEXT NOT NULL,
      first_source TEXT NOT NULL,
      first_claimed_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
      last_claimed_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
      manual_claim_count INTEGER NOT NULL DEFAULT 0,
      scheduled_claim_count INTEGER NOT NULL DEFAULT 0,
      last_result TEXT NOT NULL DEFAULT 'started',
      successful_completed_at TEXT,
      last_finished_at TEXT,
      PRIMARY KEY (automation_id, account_id, run_date)
    )`,
  ).run();

  const missingColumns: Array<{ name: string; definition: string }> = [];
  if (!(await doesColumnExist(env, "automation_daily_run_locks", "last_result"))) {
    missingColumns.push({ name: "last_result", definition: "TEXT NOT NULL DEFAULT 'started'" });
  }
  if (!(await doesColumnExist(env, "automation_daily_run_locks", "successful_completed_at"))) {
    missingColumns.push({ name: "successful_completed_at", definition: "TEXT" });
  }
  if (!(await doesColumnExist(env, "automation_daily_run_locks", "last_finished_at"))) {
    missingColumns.push({ name: "last_finished_at", definition: "TEXT" });
  }

  for (const column of missingColumns) {
    await env.DB.prepare(
      `ALTER TABLE automation_daily_run_locks ADD COLUMN ${column.name} ${column.definition}`,
    ).run();
  }

  await env.DB.prepare(
    `CREATE INDEX IF NOT EXISTS idx_automation_daily_run_locks_run_date
     ON automation_daily_run_locks (run_date, automation_id, account_id)`,
  ).run();
}

async function getAutomationDailyRunLock(
  env: Env,
  automationId: string,
  accountId: string,
  runDate: string,
): Promise<AutomationDailyRunLockRow | null> {
  await ensureAutomationDailyRunLocksTable(env);

  return env.DB.prepare(
    `SELECT
       automation_id,
       account_id,
       run_date,
       first_source,
       first_claimed_at,
       last_claimed_at,
       manual_claim_count,
       scheduled_claim_count,
       last_result,
       successful_completed_at,
       last_finished_at
     FROM automation_daily_run_locks
     WHERE automation_id = ?
       AND account_id = ?
       AND run_date = ?
     LIMIT 1`,
  )
    .bind(automationId, accountId, runDate)
    .first<AutomationDailyRunLockRow>();
}

async function claimAutomationDailyRun(
  env: Env,
  automationId: string,
  accountId: string,
  runDate: string,
  source: "manual" | "scheduled",
): Promise<{
  acquired: boolean;
  lock: AutomationDailyRunLockRow | null;
  reason: "already_ran_today" | "claimed";
}> {
  await ensureAutomationDailyRunLocksTable(env);

  const existing = await getAutomationDailyRunLock(env, automationId, accountId, runDate);
  if (!existing) {
    await env.DB.prepare(
      `INSERT INTO automation_daily_run_locks (
        automation_id,
        account_id,
        run_date,
        first_source,
        manual_claim_count,
        scheduled_claim_count,
        last_result
      )
      VALUES (?, ?, ?, ?, ?, ?, ?)`,
    )
      .bind(
        automationId,
        accountId,
        runDate,
        source,
        source === "manual" ? 1 : 0,
        source === "scheduled" ? 1 : 0,
        "started",
      )
      .run();

    const lock = await getAutomationDailyRunLock(env, automationId, accountId, runDate);
    return { acquired: true, lock, reason: "claimed" };
  }

  if (source === "scheduled" && Boolean(existing.successful_completed_at)) {
    return { acquired: false, lock: existing, reason: "already_ran_today" };
  }

  await env.DB.prepare(
    `UPDATE automation_daily_run_locks
     SET manual_claim_count = manual_claim_count + ?,
         scheduled_claim_count = scheduled_claim_count + ?,
         last_claimed_at = CURRENT_TIMESTAMP,
         last_result = 'started'
     WHERE automation_id = ?
       AND account_id = ?
       AND run_date = ?`,
  )
    .bind(
      source === "manual" ? 1 : 0,
      source === "scheduled" ? 1 : 0,
      automationId,
      accountId,
      runDate,
    )
    .run();

  const updated = await getAutomationDailyRunLock(env, automationId, accountId, runDate);
  return { acquired: true, lock: updated, reason: "claimed" };
}

async function completeAutomationDailyRun(
  env: Env,
  automationId: string,
  accountId: string,
  runDate: string,
  success: boolean,
  result: string,
): Promise<AutomationDailyRunLockRow | null> {
  await ensureAutomationDailyRunLocksTable(env);

  await env.DB.prepare(
    `UPDATE automation_daily_run_locks
     SET last_result = ?,
         last_finished_at = CURRENT_TIMESTAMP,
         successful_completed_at = CASE
           WHEN ? = 1 THEN CURRENT_TIMESTAMP
           ELSE successful_completed_at
         END
     WHERE automation_id = ?
       AND account_id = ?
       AND run_date = ?`,
  )
    .bind(
      result,
      success ? 1 : 0,
      automationId,
      accountId,
      runDate,
    )
    .run();

  return getAutomationDailyRunLock(env, automationId, accountId, runDate);
}

async function upsertThreadsPostsArchive(
  env: Env,
  threadsUserId: string,
  posts: CachedThreadsPost[],
): Promise<void> {
  await ensureThreadsPostsArchiveTable(env);

  for (const [index, post] of posts.entries()) {
    if (!post.id) {
      continue;
    }

    await env.DB.prepare(
      `INSERT INTO threads_posts_archive (
        threads_user_id,
        post_id,
        post_text,
        post_timestamp,
        post_permalink,
        post_username,
        profile_picture_url,
        views,
        likes,
        replies,
        reposts,
        quotes,
        shares,
        engagement_total,
        source_rank,
        first_seen_at,
        last_seen_at,
        last_synced_at
      )
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
      ON CONFLICT(threads_user_id, post_id) DO UPDATE SET
        post_text = excluded.post_text,
        post_timestamp = excluded.post_timestamp,
        post_permalink = excluded.post_permalink,
        post_username = excluded.post_username,
        profile_picture_url = excluded.profile_picture_url,
        views = max(threads_posts_archive.views, excluded.views),
        likes = max(threads_posts_archive.likes, excluded.likes),
        replies = max(threads_posts_archive.replies, excluded.replies),
        reposts = max(threads_posts_archive.reposts, excluded.reposts),
        quotes = max(threads_posts_archive.quotes, excluded.quotes),
        shares = max(threads_posts_archive.shares, excluded.shares),
        engagement_total = max(threads_posts_archive.engagement_total, excluded.engagement_total),
        source_rank = excluded.source_rank,
        last_seen_at = CURRENT_TIMESTAMP,
        last_synced_at = CURRENT_TIMESTAMP`,
    )
      .bind(
        threadsUserId,
        post.id,
        post.text,
        post.timestamp,
        post.permalink,
        post.username,
        post.profile_picture_url,
        post.views,
        post.likes,
        post.replies,
        post.reposts,
        post.quotes,
        post.shares,
        post.engagement_total,
        index,
      )
      .run();
  }
}

export function evaluateThreadsPostMetricsForLearning(post: CachedThreadsPost): {
  validForLearning: boolean;
  anomalyReason: string | null;
  metrics: Record<string, number>;
} {
  const metrics = {
    views: Number(post.views),
    likes: Number(post.likes),
    replies: Number(post.replies),
    reposts: Number(post.reposts),
    quotes: Number(post.quotes),
    shares: Number(post.shares),
    engagement_total: Number(post.engagement_total),
  };
  const anomalies: string[] = [];
  for (const [metric, value] of Object.entries(metrics)) {
    if (!Number.isFinite(value) || value < 0 || !Number.isInteger(value)) {
      anomalies.push(`${metric}_invalid`);
    }
  }
  const componentTotal = metrics.likes + metrics.replies + metrics.reposts + metrics.quotes + metrics.shares;
  if (metrics.views === 0 && componentTotal > 0) {
    anomalies.push("engagement_without_views");
  }
  if (metrics.views > 0) {
    for (const metric of ["likes", "replies", "reposts", "quotes", "shares"] as const) {
      if (metrics[metric] > metrics.views) {
        anomalies.push(`${metric}_exceeds_views`);
      }
    }
  }
  if (metrics.engagement_total < componentTotal) {
    anomalies.push("engagement_total_below_components");
  }
  return {
    validForLearning: anomalies.length === 0,
    anomalyReason: anomalies.length ? anomalies.join(",") : null,
    metrics,
  };
}

const OPERATOR_PERFORMANCE_EVALUATOR_VERSION = "performance-evaluator-v2";
const OPERATOR_POST_FINGERPRINT_VERSION = "post-fingerprint-v1";
export const OPERATOR_PERFORMANCE_MATURITY_CHECKPOINTS = [6, 12, 18, 24] as const;
const OPERATOR_CONTENT_FOCUS_VERSION = "content-focus-v1";
const OPERATOR_CONTENT_FOCUS_STRONG_SCORE = 65;
const OPERATOR_CONTENT_FOCUS_WEAK_SCORE = 35;
const OPERATOR_CONTENT_FOCUS_DEFAULT_ALLOCATION = { repeat: 50, expand: 25, test: 20, exploration: 5 } as const;

export type OperatorContentFocusStatus = "repeat" | "expand" | "test" | "hold" | "retire" | "blocked";
export type OperatorContentFocusCadence = "daily" | "weekly" | "monthly" | "quarterly";

type OperatorContentFocusHorizonSummary = {
  post_count: number;
  mature_count: number;
  strong_count: number;
  weak_count: number;
  median_overall: number | null;
  latest_overall: number | null;
};

type OperatorContentFocusFamilyInput = {
  cadence: OperatorContentFocusCadence;
  current_status?: OperatorContentFocusStatus | null;
  manual_lock?: boolean;
  fatigue_ratio?: number;
  horizons: Partial<Record<"immediate_24h" | "operating_7d" | "baseline_30d" | "strategic_90d" | "ytd" | "all_time", OperatorContentFocusHorizonSummary>>;
};

export function classifyOperatorContentFocusFamily(input: OperatorContentFocusFamilyInput): {
  status: OperatorContentFocusStatus;
  recommended_status: OperatorContentFocusStatus;
  confidence_label: "insufficient" | "directional" | "reliable";
  confidence_score: number;
  allocation_weight: number;
  reason: string;
} {
  const currentStatus = input.current_status ?? "test";
  const weight = (status: OperatorContentFocusStatus): number => status === "repeat" ? 1.5 : status === "expand" ? 1.25 : status === "test" ? 1 : 0;
  if (input.manual_lock || currentStatus === "blocked") {
    return {
      status: currentStatus,
      recommended_status: currentStatus,
      confidence_label: "reliable",
      confidence_score: 100,
      allocation_weight: weight(currentStatus),
      reason: "Owner-locked focus status is preserved.",
    };
  }

  const operating = input.horizons.operating_7d;
  const baseline = input.horizons.baseline_30d;
  const strategic = input.horizons.strategic_90d;
  const fatigueRatio = Math.max(0, Number(input.fatigue_ratio ?? 0));
  let recommended: OperatorContentFocusStatus = "test";
  let reason = "Evidence remains insufficient or mixed, so the family stays in controlled testing.";
  const canRetire = input.cadence === "monthly" || input.cadence === "quarterly";

  if (
    canRetire
    && Number(strategic?.mature_count ?? 0) >= 5
    && Number(strategic?.median_overall ?? 100) <= OPERATOR_CONTENT_FOCUS_WEAK_SCORE
    && Number(strategic?.weak_count ?? 0) >= 4
    && Number(strategic?.strong_count ?? 0) === 0
  ) {
    recommended = "retire";
    reason = "Repeated mature weakness across the 90-day strategic window supports retirement.";
  } else if (
    (Number(operating?.mature_count ?? 0) >= 3 && Number(operating?.median_overall ?? 100) <= 40)
    || (fatigueRatio >= 0.5 && Number(operating?.post_count ?? 0) >= 4)
  ) {
    recommended = "hold";
    reason = fatigueRatio >= 0.5
      ? "Recent use is concentrated enough to create fatigue risk, so the family should pause."
      : "Several mature seven-day results are weak, so the family should pause before more allocation.";
  } else if (
    Number(baseline?.mature_count ?? 0) >= 3
    && Number(baseline?.median_overall ?? 0) >= OPERATOR_CONTENT_FOCUS_STRONG_SCORE
    && Number(baseline?.strong_count ?? 0) >= 2
  ) {
    recommended = "repeat";
    reason = "Multiple mature 30-day results confirm a repeatable winning family.";
  } else if (
    Number(baseline?.strong_count ?? 0) >= 1
    || (Number(operating?.mature_count ?? 0) >= 2 && Number(operating?.median_overall ?? 0) >= 58)
  ) {
    recommended = "expand";
    reason = "Promising mature evidence supports controlled variations without declaring the family fully proven.";
  }

  const evidenceCount = Math.max(Number(baseline?.mature_count ?? 0), Number(strategic?.mature_count ?? 0));
  const confidenceLabel = evidenceCount >= 8 ? "reliable" : evidenceCount >= 3 ? "directional" : "insufficient";
  const effectDistance = Math.max(
    Math.abs(Number(baseline?.median_overall ?? 50) - 50),
    Math.abs(Number(strategic?.median_overall ?? 50) - 50),
  );
  const confidenceScore = Number(((Math.min(1, evidenceCount / 8) * 0.75 + Math.min(1, effectDistance / 25) * 0.25) * 100).toFixed(2));
  const status = input.cadence === "daily" && input.current_status ? currentStatus : recommended;
  return {
    status,
    recommended_status: recommended,
    confidence_label: confidenceLabel,
    confidence_score: confidenceScore,
    allocation_weight: weight(status),
    reason,
  };
}

export type OperatorContentFocusDecision = {
  role: "use_more" | "use_less" | "learn_next";
  source_card_family_id: string;
  status: OperatorContentFocusStatus;
  action: string;
  rationale: string;
};

export function buildOperatorContentFocusDailyDecisions(families: Array<{
  source_card_family_id: string;
  status: OperatorContentFocusStatus;
  recommended_status?: OperatorContentFocusStatus;
  operating_score: number | null;
  baseline_score: number | null;
  mature_count: number;
  strong_count: number;
  weak_count: number;
  fatigue_ratio: number;
}>): OperatorContentFocusDecision[] {
  const decisions: OperatorContentFocusDecision[] = [];
  const used = new Set<string>();
  const useMore = families
    .filter((family) => !["hold", "retire", "blocked"].includes(family.status))
    .filter((family) => family.strong_count > 0 || Number(family.operating_score ?? 0) >= 55)
    .sort((left, right) =>
      right.strong_count - left.strong_count
      || Number(right.operating_score ?? 0) - Number(left.operating_score ?? 0)
      || Number(right.baseline_score ?? 0) - Number(left.baseline_score ?? 0),
    )[0];
  if (useMore) {
    used.add(useMore.source_card_family_id);
    decisions.push({
      role: "use_more",
      source_card_family_id: useMore.source_card_family_id,
      status: useMore.status,
      action: "Increase near-term allocation modestly and preserve the verified winning mechanism.",
      rationale: "This family has the strongest current combination of mature wins and operating-window performance.",
    });
  }

  const useLess = families
    .filter((family) => !used.has(family.source_card_family_id) && !["retire", "blocked"].includes(family.status))
    .filter((family) => family.status === "hold" || family.fatigue_ratio >= 0.5 || (family.mature_count >= 3 && Number(family.operating_score ?? 100) <= 40))
    .sort((left, right) =>
      Number(left.operating_score ?? 100) - Number(right.operating_score ?? 100)
      || right.fatigue_ratio - left.fatigue_ratio
      || right.weak_count - left.weak_count,
    )[0];
  if (useLess) {
    used.add(useLess.source_card_family_id);
    decisions.push({
      role: "use_less",
      source_card_family_id: useLess.source_card_family_id,
      status: useLess.status,
      action: "Reduce or pause near-term allocation until new evidence justifies reuse.",
      rationale: "Recent weakness or concentration indicates underperformance or fatigue risk.",
    });
  }

  const learnNext = families
    .filter((family) => !used.has(family.source_card_family_id) && !["hold", "retire", "blocked"].includes(family.status))
    .filter((family) => family.status === "test" || family.mature_count < 3 || family.recommended_status === "expand")
    .sort((left, right) =>
      Number(right.baseline_score ?? right.operating_score ?? 50) - Number(left.baseline_score ?? left.operating_score ?? 50)
      || left.mature_count - right.mature_count,
    )[0];
  if (learnNext) {
    decisions.push({
      role: "learn_next",
      source_card_family_id: learnNext.source_card_family_id,
      status: learnNext.status,
      action: "Run one controlled variation that changes a single surface while preserving the source mechanism.",
      rationale: "This family has useful potential but not enough mature evidence for a stronger classification.",
    });
  }
  return decisions.slice(0, 3);
}

function operatorContentFocusRandomUnit(): number {
  const random = new Uint32Array(1);
  crypto.getRandomValues(random);
  return (random[0] + 1) / 4294967297;
}

export function selectOperatorContentFocusSources<T extends Record<string, unknown>>(
  candidates: T[],
  requestedCount: number,
  random: () => number = operatorContentFocusRandomUnit,
): { selected: T[]; allocation: Record<string, unknown> } {
  const count = Math.max(0, Math.trunc(requestedCount));
  const active = candidates.filter((candidate) => {
    const status = String(candidate.focus_status ?? "test") as OperatorContentFocusStatus;
    return !["hold", "retire", "blocked"].includes(status) && Number(candidate.focus_weight ?? 1) > 0;
  });
  const rawTargets = Object.entries(OPERATOR_CONTENT_FOCUS_DEFAULT_ALLOCATION).map(([key, percent]) => ({ key, raw: count * Number(percent) / 100 }));
  const targets = Object.fromEntries(rawTargets.map((item) => [item.key, Math.floor(item.raw)])) as Record<string, number>;
  let remaining = count - Object.values(targets).reduce((sum, value) => sum + value, 0);
  for (const item of [...rawTargets].sort((left, right) => (right.raw % 1) - (left.raw % 1))) {
    if (remaining <= 0) break;
    targets[item.key] += 1;
    remaining -= 1;
  }
  const weighted = (items: T[]) => [...items].map((item) => ({
    item,
    key: -Math.log(Math.max(random(), Number.EPSILON)) / Math.max(Number(item.focus_weight ?? 1), 0.05),
  })).sort((left, right) => left.key - right.key).map((entry) => entry.item);
  const buckets: Record<string, T[]> = {
    repeat: active.filter((item) => item.focus_observed === true && item.focus_status === "repeat"),
    expand: active.filter((item) => item.focus_observed === true && item.focus_status === "expand"),
    test: active.filter((item) => item.focus_observed === true && item.focus_status === "test"),
    exploration: active.filter((item) => item.focus_observed !== true),
  };
  const selected: T[] = [];
  const selectedIds = new Set<string>();
  const selectedCounts: Record<string, number> = {};
  for (const key of ["repeat", "expand", "test", "exploration"]) {
    for (const pick of weighted(buckets[key]).slice(0, targets[key] ?? 0)) {
      const id = String(pick.source_identity_key ?? pick.source_candidate_id ?? "");
      if (!id || selectedIds.has(id)) continue;
      selected.push(pick);
      selectedIds.add(id);
      selectedCounts[key] = Number(selectedCounts[key] ?? 0) + 1;
    }
  }
  for (const pick of weighted(active.filter((item) => {
    const id = String(item.source_identity_key ?? item.source_candidate_id ?? "");
    return id && !selectedIds.has(id);
  }))) {
    if (selected.length >= count) break;
    const id = String(pick.source_identity_key ?? pick.source_candidate_id ?? "");
    if (!id || selectedIds.has(id)) continue;
    selected.push(pick);
    selectedIds.add(id);
  }
  return {
    selected: selected.slice(0, count),
    allocation: {
      percentages: OPERATOR_CONTENT_FOCUS_DEFAULT_ALLOCATION,
      targets,
      selected_counts: selectedCounts,
      excluded_zero_allocation_count: candidates.length - active.length,
    },
  };
}

type OperatorMetricRecord = {
  views: number;
  likes: number;
  replies: number;
  reposts: number;
  quotes: number;
  shares: number;
  engagement_total: number;
};

type OperatorPerformanceScoreRecord = {
  reach: number;
  resonance: number;
  propagation: number;
  conversation: number;
  overall: number;
};

function stableOperatorTextHash(value: string): string {
  let hash = 2166136261;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return `fnv1a_${(hash >>> 0).toString(16).padStart(8, "0")}`;
}

function operatorRecord(value: unknown): Record<string, unknown> {
  return value && typeof value === "object" && !Array.isArray(value)
    ? value as Record<string, unknown>
    : {};
}

function operatorArray(value: unknown): unknown[] {
  if (Array.isArray(value)) return value;
  const parsed = safeParseJsonString(String(value ?? "[]"));
  return Array.isArray(parsed) ? parsed : [];
}

function normalizeOperatorFeatureValue(value: unknown, fallback = "unknown"): string {
  return normalizeGptStrategyToken(value, 120) ?? fallback;
}

function operatorMetricRecord(value: unknown): OperatorMetricRecord {
  const record = operatorRecord(value);
  return {
    views: Math.max(0, Number(record.views ?? 0)),
    likes: Math.max(0, Number(record.likes ?? 0)),
    replies: Math.max(0, Number(record.replies ?? 0)),
    reposts: Math.max(0, Number(record.reposts ?? 0)),
    quotes: Math.max(0, Number(record.quotes ?? 0)),
    shares: Math.max(0, Number(record.shares ?? 0)),
    engagement_total: Math.max(0, Number(record.engagement_total ?? 0)),
  };
}

function operatorScoreRecord(value: unknown): OperatorPerformanceScoreRecord {
  const record = operatorRecord(value);
  return {
    reach: Number(record.reach ?? 50),
    resonance: Number(record.resonance ?? 50),
    propagation: Number(record.propagation ?? 50),
    conversation: Number(record.conversation ?? 50),
    overall: Number(record.overall ?? 50),
  };
}

function operatorAverage(values: number[]): number {
  const valid = values.filter((value) => Number.isFinite(value));
  return valid.length ? valid.reduce((sum, value) => sum + value, 0) / valid.length : 0;
}

function operatorPercentileRank(value: number, values: number[]): number {
  const valid = values.filter((candidate) => Number.isFinite(candidate));
  if (!valid.length || !Number.isFinite(value)) return 50;
  const below = valid.filter((candidate) => candidate < value).length;
  const equal = valid.filter((candidate) => candidate === value).length;
  return Number((((below + equal * 0.5) / valid.length) * 100).toFixed(2));
}

function inferOperatorOpeningType(text: string): string {
  const normalized = text.trim().toLowerCase();
  if (!normalized) return "empty";
  if (normalized.endsWith("?") || /^(what|why|how|when do|do you|are you)\b/.test(normalized)) return "question";
  if (/^(repeat after me|say this|remember|trust|believe|stop|never|do not|don't|let go|listen)\b/.test(normalized)) return "directive";
  if (/^(when|if|whenever|once)\b/.test(normalized)) return "conditional";
  if (/^(you|your)\b/.test(normalized)) return "direct_address";
  if (/^(i|i'm|im|my)\b/.test(normalized)) return "first_person";
  return "statement";
}

function inferOperatorPayoffStyle(text: string): string {
  const trimmed = text.trim();
  if (!trimmed) return "empty";
  const segments = trimmed.split(/\n|(?<=[.!?])\s+/).map((segment) => segment.trim()).filter(Boolean);
  const ending = segments[segments.length - 1] ?? trimmed;
  if (ending.endsWith("?")) return "question";
  const letters = ending.replace(/[^A-Za-z]/g, "");
  if (letters.length >= 4 && letters === letters.toUpperCase()) return "all_caps_declaration";
  if (/^(believe|trust|remember|stop|never|do not|don't|keep|choose|let)\b/i.test(ending)) return "directive";
  if (segments.length > 1 && normalizeComparableText(segments[0]) === normalizeComparableText(ending)) return "repeated_refrain";
  return "declaration";
}

function inferOperatorTone(text: string, metadata: Record<string, unknown>): string {
  const explicit = normalizeGptStrategyToken(metadata.tone ?? metadata.voice ?? metadata.emotional_tone, 80);
  if (explicit) return explicit;
  const letters = text.replace(/[^A-Za-z]/g, "");
  const uppercaseRatio = letters.length ? letters.replace(/[^A-Z]/g, "").length / letters.length : 0;
  if (text.includes("!") || uppercaseRatio >= 0.35) return "forceful";
  if (/\b(maybe|perhaps|sometimes|wonder|realize|notice)\b/i.test(text)) return "reflective";
  if (text.includes("?")) return "inquisitive";
  return "direct";
}

export function buildOperatorPostFingerprint(input: {
  text: string;
  strategy?: Record<string, unknown> | null;
  sourceCard?: Record<string, unknown> | null;
  sourceSelection?: Record<string, unknown> | null;
  adaptationPlan?: Record<string, unknown> | null;
}): Record<string, unknown> {
  const text = input.text.trim();
  const strategy = operatorRecord(input.strategy);
  const parsedStrategyMetadata = safeParseJsonString(String(strategy.metadata_json ?? ""));
  const strategyMetadata = operatorRecord(strategy.metadata ?? parsedStrategyMetadata);
  const sourceCard = operatorRecord(input.sourceCard);
  const sourceSelection = operatorRecord(input.sourceSelection);
  const adaptationPlan = operatorRecord(input.adaptationPlan);
  const lines = text.split(/\n+/).map((line) => line.trim()).filter(Boolean);
  const sentences = text.split(/[.!?]+|\n+/).map((sentence) => sentence.trim()).filter(Boolean);
  const words = text.split(/\s+/).filter(Boolean);
  const structure = lines.length > 1
    ? "line_broken"
    : sentences.length <= 1
      ? "single_sentence"
      : sentences.length === 2
        ? "two_sentence"
        : "multi_sentence";
  const lengthBucket = words.length <= 8 ? "micro" : words.length <= 20 ? "short" : words.length <= 40 ? "medium" : "long";
  return {
    version: OPERATOR_POST_FINGERPRINT_VERSION,
    text_hash: stableOperatorTextHash(text),
    hook_style: normalizeOperatorFeatureValue(strategy.hook_style ?? strategyMetadata.hook_style, "unclassified"),
    topic: normalizeOperatorFeatureValue(strategy.pillar ?? sourceCard.lane_key ?? strategyMetadata.topic, "unclassified"),
    format: normalizeOperatorFeatureValue(strategy.format, structure),
    intent: normalizeOperatorFeatureValue(strategy.intent ?? strategyMetadata.intent, "unclassified"),
    experiment: normalizeOperatorFeatureValue(strategy.experiment, "none"),
    novelty_level: normalizeOperatorFeatureValue(strategy.novelty_level, "unclassified"),
    source_mechanism: normalizeOperatorFeatureValue(sourceCard.source_mechanism, "unclassified"),
    audience_reward: normalizeOperatorFeatureValue(sourceCard.required_product ?? strategyMetadata.audience_reward, "unclassified"),
    opening_type: inferOperatorOpeningType(text),
    structure,
    length_bucket: lengthBucket,
    payoff_style: inferOperatorPayoffStyle(text),
    tone: inferOperatorTone(text, strategyMetadata),
    direct_address: /\b(you|your|you're|youre)\b/i.test(text) ? "yes" : "no",
    adaptation_style: normalizeOperatorFeatureValue(
      adaptationPlan.adaptation_style ?? adaptationPlan.variation_axis ?? adaptationPlan.experiment_key ?? strategy.experiment,
      "baseline",
    ),
    source_identity_key: normalizeOperatorFeatureValue(sourceSelection.source_identity_key ?? sourceCard.family_id, "unlinked"),
    word_count: words.length,
    sentence_count: sentences.length,
    line_count: lines.length,
  };
}

export function buildOperatorMaturityObservation(input: {
  checkpointHours: number;
  currentMetrics: Record<string, unknown>;
  currentAgeHours: number;
  previousMetrics?: Record<string, unknown> | null;
  previousAgeHours?: number | null;
}): {
  metrics: OperatorMetricRecord;
  rates: Record<string, number>;
  velocity: Record<string, number>;
  distribution_state: "initial" | "accelerating" | "sustained" | "stalled";
} {
  const metrics = operatorMetricRecord(input.currentMetrics);
  const previous = input.previousMetrics ? operatorMetricRecord(input.previousMetrics) : null;
  const denominator = Math.max(metrics.views, 1);
  const currentAge = Math.max(input.currentAgeHours, 0.25);
  const previousAge = Math.max(Number(input.previousAgeHours ?? 0), 0);
  const intervalHours = previous && previousAge > 0 ? Math.max(currentAge - previousAge, 0.25) : currentAge;
  const delta = (key: keyof OperatorMetricRecord) => previous ? Math.max(0, metrics[key] - previous[key]) : metrics[key];
  const intervalViewVelocity = delta("views") / intervalHours;
  const previousCumulativeVelocity = previous && previousAge > 0 ? previous.views / previousAge : 0;
  const velocityRatio = previousCumulativeVelocity > 0 ? intervalViewVelocity / previousCumulativeVelocity : 1;
  const distributionState = !previous
    ? "initial"
    : intervalViewVelocity <= 0
      ? "stalled"
      : velocityRatio >= 1.25
        ? "accelerating"
        : velocityRatio >= 0.35
          ? "sustained"
          : "stalled";
  return {
    metrics,
    rates: {
      like_rate: Number((metrics.likes / denominator).toFixed(6)),
      propagation_rate: Number(((metrics.reposts + metrics.quotes + metrics.shares) / denominator).toFixed(6)),
      conversation_rate: Number((metrics.replies / denominator).toFixed(6)),
      engagement_rate: Number(((metrics.likes + metrics.replies + metrics.reposts + metrics.quotes + metrics.shares) / denominator).toFixed(6)),
    },
    velocity: {
      cumulative_views_per_hour: Number((metrics.views / currentAge).toFixed(4)),
      interval_views_per_hour: Number(intervalViewVelocity.toFixed(4)),
      interval_likes_per_hour: Number((delta("likes") / intervalHours).toFixed(4)),
      interval_reposts_per_hour: Number((delta("reposts") / intervalHours).toFixed(4)),
      interval_replies_per_hour: Number((delta("replies") / intervalHours).toFixed(4)),
      velocity_ratio_to_prior_cumulative: Number(velocityRatio.toFixed(4)),
    },
    distribution_state: distributionState,
  };
}

function operatorFingerprintDimensions(fingerprint: Record<string, unknown>): Array<{ dimension: string; feature: string }> {
  return [
    "hook_style", "topic", "format", "intent", "experiment", "novelty_level",
    "source_mechanism", "audience_reward", "opening_type", "structure", "length_bucket",
    "payoff_style", "tone", "direct_address", "adaptation_style",
  ].map((dimension) => ({ dimension, feature: normalizeOperatorFeatureValue(fingerprint[dimension], "unknown") }))
    .filter((item) => item.feature !== "unknown" && item.feature !== "unclassified");
}

