function chooseOperatorCheckpointSnapshot(
  rows: Array<Record<string, unknown>>,
  publishedAtMs: number,
  checkpointHours: number,
): { row: Record<string, unknown>; ageHours: number } | null {
  const tolerance = checkpointHours >= 48 ? 8 : 7;
  return rows.map((row) => {
    const capturedMs = Date.parse(String(row.captured_at ?? ""));
    return { row, ageHours: Number.isFinite(capturedMs) ? (capturedMs - publishedAtMs) / 3600000 : Number.NaN };
  }).filter((candidate) => Number.isFinite(candidate.ageHours)
    && candidate.ageHours >= checkpointHours
    && candidate.ageHours <= checkpointHours + tolerance)
    .sort((left, right) => left.ageHours - right.ageHours)[0] ?? null;
}

type OperatorContentFocusScoreRow = {
  published_post_id: string;
  posted_at_ms: number;
  checkpoint_hours: number;
  overall: number;
  source_card_family_id: string;
  source_identity_key: string;
  source_card_id: string | null;
  source_mechanism: string | null;
  required_product: string | null;
  recommended_direction: string | null;
  transformation_contract: Record<string, unknown>;
  forbidden_surfaces: unknown[];
  danger_surfaces: unknown[];
  fail_conditions: unknown[];
};

function operatorContentFocusSummary(rows: OperatorContentFocusScoreRow[]): OperatorContentFocusHorizonSummary {
  const mature = rows.filter((row) => row.checkpoint_hours === 24);
  const scores = mature.map((row) => row.overall).filter(Number.isFinite).sort((left, right) => left - right);
  const latest = [...rows].sort((left, right) => right.posted_at_ms - left.posted_at_ms || right.checkpoint_hours - left.checkpoint_hours)[0];
  return {
    post_count: new Set(rows.map((row) => row.published_post_id)).size,
    mature_count: mature.length,
    strong_count: mature.filter((row) => row.overall >= OPERATOR_CONTENT_FOCUS_STRONG_SCORE).length,
    weak_count: mature.filter((row) => row.overall <= OPERATOR_CONTENT_FOCUS_WEAK_SCORE).length,
    median_overall: scores.length ? Number(calculateMedian(scores).toFixed(2)) : null,
    latest_overall: latest ? Number(latest.overall.toFixed(2)) : null,
  };
}

function operatorContentFocusPeriodKey(cadence: OperatorContentFocusCadence, anchorDate: string): string {
  if (cadence === "daily") return anchorDate;
  const date = new Date(`${anchorDate}T12:00:00.000Z`);
  if (cadence === "monthly") return anchorDate.slice(0, 7);
  if (cadence === "quarterly") return `${date.getUTCFullYear()}-Q${Math.floor(date.getUTCMonth() / 3) + 1}`;
  const day = date.getUTCDay() || 7;
  date.setUTCDate(date.getUTCDate() - day + 1);
  return date.toISOString().slice(0, 10);
}

function operatorContentFocusWindowRows(
  rows: OperatorContentFocusScoreRow[],
  nowMs: number,
  days: number | null,
  ytd = false,
): OperatorContentFocusScoreRow[] {
  if (ytd) {
    const yearStart = Date.UTC(new Date(nowMs).getUTCFullYear(), 0, 1);
    return rows.filter((row) => row.posted_at_ms >= yearStart);
  }
  if (days === null) return rows;
  const cutoff = nowMs - days * 86400000;
  return rows.filter((row) => row.posted_at_ms >= cutoff);
}

function operatorContentFocusHorizons(rows: OperatorContentFocusScoreRow[], nowMs: number): OperatorContentFocusFamilyInput["horizons"] {
  const latestByPost = new Map<string, OperatorContentFocusScoreRow>();
  for (const row of rows) {
    const existing = latestByPost.get(row.published_post_id);
    if (!existing || row.checkpoint_hours > existing.checkpoint_hours) latestByPost.set(row.published_post_id, row);
  }
  const immediateRows = Array.from(latestByPost.values()).filter((row) => row.posted_at_ms >= nowMs - 86400000);
  return {
    immediate_24h: operatorContentFocusSummary(immediateRows),
    operating_7d: operatorContentFocusSummary(operatorContentFocusWindowRows(rows, nowMs, 7)),
    baseline_30d: operatorContentFocusSummary(operatorContentFocusWindowRows(rows, nowMs, 30)),
    strategic_90d: operatorContentFocusSummary(operatorContentFocusWindowRows(rows, nowMs, 90)),
    ytd: operatorContentFocusSummary(operatorContentFocusWindowRows(rows, nowMs, null, true)),
    all_time: operatorContentFocusSummary(rows),
  };
}

async function loadOperatorContentFocusRows(env: Env, brandKey: GptBrandKey): Promise<OperatorContentFocusScoreRow[]> {
  const rows = await env.DB.prepare(
    `SELECT s.published_post_id, s.checkpoint_hours, s.scores_json, a.post_timestamp,
            f.source_card_id, c.family_id, fam.source_identity_key, c.source_mechanism,
            c.required_product, c.recommended_direction, c.transformation_contract_json,
            c.forbidden_surfaces_json, c.danger_surfaces_json, c.fail_conditions_json
     FROM operator_post_performance_scores s
     JOIN operator_post_fingerprints f ON f.brand_key = s.brand_key AND f.published_post_id = s.published_post_id
     JOIN operator_source_cards c ON c.id = f.source_card_id AND c.brand_key = s.brand_key
     JOIN operator_source_card_families fam ON fam.id = c.family_id AND fam.brand_key = s.brand_key
     JOIN threads_posts_archive a ON a.post_id = s.published_post_id
     WHERE s.brand_key = ? AND s.valid_for_learning = 1`,
  ).bind(brandKey).all<Record<string, unknown>>();
  return (rows.results ?? []).map((row) => ({
    published_post_id: String(row.published_post_id ?? ""),
    posted_at_ms: Date.parse(String(row.post_timestamp ?? "")),
    checkpoint_hours: Number(row.checkpoint_hours),
    overall: operatorScoreRecord(safeParseJsonString(String(row.scores_json ?? "{}"))).overall,
    source_card_family_id: String(row.family_id ?? ""),
    source_identity_key: String(row.source_identity_key ?? ""),
    source_card_id: row.source_card_id ? String(row.source_card_id) : null,
    source_mechanism: normalizeOperatorText(row.source_mechanism, 4000, true),
    required_product: normalizeOperatorText(row.required_product, 4000, true),
    recommended_direction: normalizeOperatorText(row.recommended_direction, 4000, true),
    transformation_contract: operatorRecord(safeParseJsonString(String(row.transformation_contract_json ?? "{}"))),
    forbidden_surfaces: operatorArray(row.forbidden_surfaces_json),
    danger_surfaces: operatorArray(row.danger_surfaces_json),
    fail_conditions: operatorArray(row.fail_conditions_json),
  })).filter((row) => row.published_post_id && row.source_card_family_id && row.source_identity_key
    && Number.isFinite(row.posted_at_ms) && Number.isFinite(row.overall));
}

async function buildOperatorContentFocusFamilies(
  env: Env,
  brandKey: GptBrandKey,
  authority: OperatorContentFocusCadence,
  nowMs: number,
): Promise<{ families: Array<Record<string, unknown>>; current_by_family: Map<string, Record<string, unknown>> }> {
  const parsedRows = await loadOperatorContentFocusRows(env, brandKey);
  const currentRows = await env.DB.prepare(
    `SELECT * FROM operator_content_focus_family_states WHERE brand_key = ?`,
  ).bind(brandKey).all<Record<string, unknown>>();
  const currentByFamily = new Map((currentRows.results ?? []).map((row) => [String(row.source_card_family_id), row]));
  const rowsByFamily = new Map<string, OperatorContentFocusScoreRow[]>();
  for (const row of parsedRows) {
    const rows = rowsByFamily.get(row.source_card_family_id) ?? [];
    rows.push(row);
    rowsByFamily.set(row.source_card_family_id, rows);
  }
  const totalRecentPosts = new Set(
    operatorContentFocusWindowRows(parsedRows, nowMs, 7).map((row) => row.published_post_id),
  ).size;
  const families: Array<Record<string, unknown>> = [];
  for (const [familyId, rows] of rowsByFamily) {
    const current = currentByFamily.get(familyId);
    const horizons = operatorContentFocusHorizons(rows, nowMs);
    const recentCount = Number(horizons.operating_7d?.post_count ?? 0);
    const fatigueRatio = totalRecentPosts ? recentCount / totalRecentPosts : 0;
    const currentStatus = (normalizeOperatorText(current?.status, 20, true) ?? "test") as OperatorContentFocusStatus;
    const classification = classifyOperatorContentFocusFamily({
      cadence: authority,
      current_status: currentStatus,
      manual_lock: Number(current?.manual_lock ?? 0) === 1 || currentStatus === "retire",
      fatigue_ratio: fatigueRatio,
      horizons,
    });
    const reference = [...rows].sort((left, right) => right.posted_at_ms - left.posted_at_ms)[0];
    families.push({
      source_card_family_id: familyId,
      source_identity_key: reference.source_identity_key,
      source_card_id: reference.source_card_id,
      status: classification.status,
      recommended_status: classification.recommended_status,
      confidence_score: classification.confidence_score,
      confidence_label: classification.confidence_label,
      allocation_weight: classification.allocation_weight,
      decision_reason: classification.reason,
      fatigue_ratio: Number(fatigueRatio.toFixed(4)),
      horizons,
      reuse_directives: {
        source_mechanism: reference.source_mechanism,
        required_product: reference.required_product,
        transformation_contract: reference.transformation_contract,
        recommended_direction: reference.recommended_direction,
      },
      stop_directives: {
        forbidden_surfaces: reference.forbidden_surfaces,
        danger_surfaces: reference.danger_surfaces,
        fail_conditions: reference.fail_conditions,
      },
    });
  }
  return { families, current_by_family: currentByFamily };
}

function operatorContentFocusDailyCandidates(families: Array<Record<string, unknown>>): Array<{
  source_card_family_id: string;
  status: OperatorContentFocusStatus;
  recommended_status: OperatorContentFocusStatus;
  operating_score: number | null;
  baseline_score: number | null;
  mature_count: number;
  strong_count: number;
  weak_count: number;
  fatigue_ratio: number;
}> {
  return families.map((family) => {
    const horizons = family.horizons as OperatorContentFocusFamilyInput["horizons"];
    return {
      source_card_family_id: String(family.source_card_family_id),
      status: family.status as OperatorContentFocusStatus,
      recommended_status: family.recommended_status as OperatorContentFocusStatus,
      operating_score: horizons.operating_7d?.median_overall ?? null,
      baseline_score: horizons.baseline_30d?.median_overall ?? null,
      mature_count: Number(horizons.baseline_30d?.mature_count ?? 0),
      strong_count: Number(horizons.baseline_30d?.strong_count ?? 0),
      weak_count: Number(horizons.operating_7d?.weak_count ?? 0),
      fatigue_ratio: Number(family.fatigue_ratio ?? 0),
    };
  });
}

async function refreshOperatorPerformanceEvaluator(
  env: Env,
  brandKey: GptBrandKey,
  accountId: string,
  threadsUserId: string,
): Promise<Record<string, unknown>> {
    await ensureOperatorPostMetricSnapshotsTable(env);
  await ensureOperatorPerformanceEvaluatorTables(env);
  const checkpointPlaceholders = OPERATOR_PERFORMANCE_MATURITY_CHECKPOINTS.map(() => "?").join(", ");
  await env.DB.prepare(
    `UPDATE operator_post_performance_scores
     SET valid_for_learning = 0, updated_at = CURRENT_TIMESTAMP
     WHERE brand_key = ?
       AND checkpoint_hours NOT IN (${checkpointPlaceholders})`,
  ).bind(brandKey, ...OPERATOR_PERFORMANCE_MATURITY_CHECKPOINTS).run();
  const postRows = await env.DB.prepare(
    `SELECT
       a.post_id AS published_post_id,
       a.post_text,
       a.post_timestamp,
       s.id AS scheduled_post_id,
       s.published_at,
       d.id AS draft_id,
       d.source_card_id,
       r.adaptation_plan_json,
       t.pillar,
       t.hook_style,
       t.format,
       t.intent,
       t.experiment,
       t.novelty_level,
       t.metadata_json AS strategy_metadata_json,
       c.family_id,
       c.lane_key,
       c.source_mechanism,
       c.required_product,
       c.recommended_direction,
       c.source_selection_id,
       sel.source_identity_key
     FROM threads_posts_archive a
     INNER JOIN (
       SELECT DISTINCT published_post_id
       FROM operator_post_metric_snapshots
       WHERE brand_key = ?
     ) snap ON snap.published_post_id = a.post_id
     LEFT JOIN scheduled_posts s
       ON s.threads_user_id = a.threads_user_id
      AND s.published_post_id = a.post_id
     LEFT JOIN gpt_generation_drafts d
       ON d.scheduled_post_id = s.id
      AND d.account_id = ?
     LEFT JOIN gpt_generation_runs r ON r.id = d.run_id
     LEFT JOIN gpt_post_strategy_tags t ON t.scheduled_post_id = s.id
     LEFT JOIN operator_source_cards c
       ON c.id = d.source_card_id
      AND c.brand_key = ?
     LEFT JOIN operator_source_selections sel ON sel.id = c.source_selection_id
     WHERE a.threads_user_id = ?
     ORDER BY datetime(a.post_timestamp) DESC, s.id DESC
     LIMIT 250`,
  ).bind(brandKey, accountId, brandKey, threadsUserId).all<Record<string, unknown>>();
  const postsById = new Map<string, Record<string, unknown>>();
  for (const row of postRows.results ?? []) {
    const postId = String(row.published_post_id ?? "");
    if (postId && !postsById.has(postId)) postsById.set(postId, row);
  }
  const snapshotRows = await env.DB.prepare(
    `SELECT id, published_post_id, metrics_json, captured_at
     FROM operator_post_metric_snapshots
     WHERE brand_key = ? AND valid_for_learning = 1
     ORDER BY published_post_id ASC, datetime(captured_at) ASC, datetime(created_at) ASC`,
  ).bind(brandKey).all<Record<string, unknown>>();
  const snapshotsByPost = new Map<string, Array<Record<string, unknown>>>();
  for (const row of snapshotRows.results ?? []) {
    const postId = String(row.published_post_id ?? "");
    if (!postId) continue;
    const rows = snapshotsByPost.get(postId) ?? [];
    rows.push(row);
    snapshotsByPost.set(postId, rows);
  }

  let fingerprintedPosts = 0;
  let maturityScores = 0;
  for (const [postId, row] of postsById) {
    const text = String(row.post_text ?? "");
    const publishedAtMs = Date.parse(String(row.post_timestamp ?? row.published_at ?? ""));
    if (!text || !Number.isFinite(publishedAtMs)) continue;
    const fingerprint = buildOperatorPostFingerprint({
      text,
      strategy: {
        pillar: row.pillar,
        hook_style: row.hook_style,
        format: row.format,
        intent: row.intent,
        experiment: row.experiment,
        novelty_level: row.novelty_level,
        metadata: safeParseJsonString(String(row.strategy_metadata_json ?? "")),
      },
      sourceCard: {
        family_id: row.family_id,
        lane_key: row.lane_key,
        source_mechanism: row.source_mechanism,
        required_product: row.required_product,
        recommended_direction: row.recommended_direction,
      },
      sourceSelection: { source_identity_key: row.source_identity_key },
      adaptationPlan: operatorRecord(safeParseJsonString(String(row.adaptation_plan_json ?? ""))),
    });
    await env.DB.prepare(
      `INSERT INTO operator_post_fingerprints (
        id, brand_key, published_post_id, scheduled_post_id, draft_id, source_card_id,
        source_selection_id, text_hash, fingerprint_version, fingerprint_json
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT(brand_key, published_post_id) DO UPDATE SET
        scheduled_post_id = excluded.scheduled_post_id,
        draft_id = excluded.draft_id,
        source_card_id = excluded.source_card_id,
        source_selection_id = excluded.source_selection_id,
        text_hash = excluded.text_hash,
        fingerprint_version = excluded.fingerprint_version,
        fingerprint_json = excluded.fingerprint_json,
        updated_at = CURRENT_TIMESTAMP`,
    ).bind(
      crypto.randomUUID(), brandKey, postId,
      row.scheduled_post_id === null || row.scheduled_post_id === undefined ? null : Number(row.scheduled_post_id),
      row.draft_id ? String(row.draft_id) : null,
      row.source_card_id ? String(row.source_card_id) : null,
      row.source_selection_id ? String(row.source_selection_id) : null,
      String(fingerprint.text_hash ?? ""), OPERATOR_POST_FINGERPRINT_VERSION,
      normalizeOperatorJson(fingerprint, {}),
    ).run();
    fingerprintedPosts += 1;

    let previousSelection: { row: Record<string, unknown>; ageHours: number } | null = null;
    for (const checkpointHours of OPERATOR_PERFORMANCE_MATURITY_CHECKPOINTS) {
      const selection = chooseOperatorCheckpointSnapshot(snapshotsByPost.get(postId) ?? [], publishedAtMs, checkpointHours);
      if (!selection) continue;
      const currentMetrics = operatorRecord(safeParseJsonString(String(selection.row.metrics_json ?? "{}")));
      const previousMetrics = previousSelection
        ? operatorRecord(safeParseJsonString(String(previousSelection.row.metrics_json ?? "{}")))
        : null;
      const observation = buildOperatorMaturityObservation({
        checkpointHours,
        currentMetrics,
        currentAgeHours: selection.ageHours,
        previousMetrics,
        previousAgeHours: previousSelection?.ageHours ?? null,
      });
      await env.DB.prepare(
        `INSERT INTO operator_post_performance_scores (
          id, brand_key, published_post_id, checkpoint_hours, snapshot_id, captured_at,
          post_age_hours, metrics_json, rates_json, velocity_json, scores_json,
          distribution_state, valid_for_learning, evaluator_version
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 1, ?)
        ON CONFLICT(brand_key, published_post_id, checkpoint_hours) DO UPDATE SET
          snapshot_id = excluded.snapshot_id,
          captured_at = excluded.captured_at,
          post_age_hours = excluded.post_age_hours,
          metrics_json = excluded.metrics_json,
          rates_json = excluded.rates_json,
          velocity_json = excluded.velocity_json,
          distribution_state = excluded.distribution_state,
          valid_for_learning = 1,
          evaluator_version = excluded.evaluator_version,
          updated_at = CURRENT_TIMESTAMP`,
      ).bind(
        crypto.randomUUID(), brandKey, postId, checkpointHours,
        String(selection.row.id), String(selection.row.captured_at), Number(selection.ageHours.toFixed(3)),
        normalizeOperatorJson(observation.metrics, {}), normalizeOperatorJson(observation.rates, {}),
        normalizeOperatorJson(observation.velocity, {}),
        normalizeOperatorJson({ reach: 50, resonance: 50, propagation: 50, conversation: 50, overall: 50 }, {}),
        observation.distribution_state, OPERATOR_PERFORMANCE_EVALUATOR_VERSION,
      ).run();
      maturityScores += 1;
      previousSelection = selection;
    }
  }

  const scoreRows = await env.DB.prepare(
    `SELECT id, published_post_id, checkpoint_hours, metrics_json, rates_json, velocity_json, scores_json
     FROM operator_post_performance_scores
     WHERE brand_key = ? AND valid_for_learning = 1`,
  ).bind(brandKey).all<Record<string, unknown>>();
  const byCheckpoint = new Map<number, Array<Record<string, unknown>>>();
  for (const row of scoreRows.results ?? []) {
    const checkpoint = Number(row.checkpoint_hours);
    const rows = byCheckpoint.get(checkpoint) ?? [];
    rows.push(row);
    byCheckpoint.set(checkpoint, rows);
  }
  for (const rows of byCheckpoint.values()) {
    const parsed = rows.map((row) => ({
      row,
      metrics: operatorMetricRecord(safeParseJsonString(String(row.metrics_json ?? "{}"))),
      rates: operatorRecord(safeParseJsonString(String(row.rates_json ?? "{}"))),
      velocity: operatorRecord(safeParseJsonString(String(row.velocity_json ?? "{}"))),
    }));
    const views = parsed.map((item) => item.metrics.views);
    const cumulativeVelocity = parsed.map((item) => Number(item.velocity.cumulative_views_per_hour ?? 0));
    const intervalVelocity = parsed.map((item) => Number(item.velocity.interval_views_per_hour ?? 0));
    const likeRates = parsed.map((item) => Number(item.rates.like_rate ?? 0));
    const propagationRates = parsed.map((item) => Number(item.rates.propagation_rate ?? 0));
    const conversationRates = parsed.map((item) => Number(item.rates.conversation_rate ?? 0));
    for (const item of parsed) {
      const reach = operatorAverage([
        operatorPercentileRank(item.metrics.views, views),
        operatorPercentileRank(Number(item.velocity.cumulative_views_per_hour ?? 0), cumulativeVelocity),
        operatorPercentileRank(Number(item.velocity.interval_views_per_hour ?? 0), intervalVelocity),
      ]);
      const resonance = operatorPercentileRank(Number(item.rates.like_rate ?? 0), likeRates);
      const propagation = operatorPercentileRank(Number(item.rates.propagation_rate ?? 0), propagationRates);
      const conversation = operatorPercentileRank(Number(item.rates.conversation_rate ?? 0), conversationRates);
      const scores = {
        reach: Number(reach.toFixed(2)),
        resonance: Number(resonance.toFixed(2)),
        propagation: Number(propagation.toFixed(2)),
        conversation: Number(conversation.toFixed(2)),
        overall: Number(operatorAverage([reach, resonance, propagation, conversation]).toFixed(2)),
      };
      await env.DB.prepare(
        `UPDATE operator_post_performance_scores SET scores_json = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ?`,
      ).bind(normalizeOperatorJson(scores, {}), item.row.id).run();
      item.row.scores_json = normalizeOperatorJson(scores, {});
    }
  }

  await env.DB.prepare(`UPDATE operator_performance_evidence SET status = 'stale', updated_at = CURRENT_TIMESTAMP WHERE brand_key = ?`).bind(brandKey).run();
  await env.DB.prepare(`UPDATE operator_performance_hypotheses SET status = 'stale', updated_at = CURRENT_TIMESTAMP WHERE brand_key = ?`).bind(brandKey).run();
  const joinedRows = await env.DB.prepare(
    `SELECT s.checkpoint_hours, s.scores_json, s.rates_json, f.fingerprint_json
     FROM operator_post_performance_scores s
     INNER JOIN operator_post_fingerprints f
       ON f.brand_key = s.brand_key AND f.published_post_id = s.published_post_id
     WHERE s.brand_key = ? AND s.valid_for_learning = 1`,
  ).bind(brandKey).all<Record<string, unknown>>();
  const joinedByCheckpoint = new Map<number, Array<Record<string, unknown>>>();
  for (const row of joinedRows.results ?? []) {
    const checkpoint = Number(row.checkpoint_hours);
    const rows = joinedByCheckpoint.get(checkpoint) ?? [];
    rows.push(row);
    joinedByCheckpoint.set(checkpoint, rows);
  }
  const evidenceRows: Array<Record<string, unknown>> = [];
  for (const [checkpointHours, rows] of joinedByCheckpoint) {
    const baselineOverall = calculateMedian(rows.map((row) => operatorScoreRecord(safeParseJsonString(String(row.scores_json ?? "{}"))).overall));
    const groups = new Map<string, { dimension: string; feature: string; rows: Array<Record<string, unknown>> }>();
    for (const row of rows) {
      const fingerprint = operatorRecord(safeParseJsonString(String(row.fingerprint_json ?? "{}")));
      for (const item of operatorFingerprintDimensions(fingerprint)) {
        const key = `${item.dimension}:${item.feature}`;
        const group = groups.get(key) ?? { ...item, rows: [] };
        group.rows.push(row);
        groups.set(key, group);
      }
    }
    for (const group of groups.values()) {
      const scores = group.rows.map((row) => operatorScoreRecord(safeParseJsonString(String(row.scores_json ?? "{}"))));
      const rates = group.rows.map((row) => operatorRecord(safeParseJsonString(String(row.rates_json ?? "{}"))));
      const medians = {
        overall_score: Number(calculateMedian(scores.map((score) => score.overall)).toFixed(2)),
        reach_score: Number(calculateMedian(scores.map((score) => score.reach)).toFixed(2)),
        resonance_score: Number(calculateMedian(scores.map((score) => score.resonance)).toFixed(2)),
        propagation_score: Number(calculateMedian(scores.map((score) => score.propagation)).toFixed(2)),
        conversation_score: Number(calculateMedian(scores.map((score) => score.conversation)).toFixed(2)),
        like_rate: Number(calculateMedian(rates.map((rate) => Number(rate.like_rate ?? 0))).toFixed(6)),
        propagation_rate: Number(calculateMedian(rates.map((rate) => Number(rate.propagation_rate ?? 0))).toFixed(6)),
        conversation_rate: Number(calculateMedian(rates.map((rate) => Number(rate.conversation_rate ?? 0))).toFixed(6)),
      };
      const effectValue = medians.overall_score - baselineOverall;
      const sampleSize = group.rows.length;
      const confidenceScore = Number(((Math.min(1, sampleSize / 8) * 0.75 + Math.min(1, Math.abs(effectValue) / 20) * 0.25) * 100).toFixed(2));
      const confidenceLabel = sampleSize >= 8 ? "reliable" : sampleSize >= 3 ? "directional" : "insufficient";
      const direction = effectValue >= 5 ? "positive" : effectValue <= -5 ? "negative" : "neutral";
      const effect = {
        overall_score_vs_cohort: Number(effectValue.toFixed(2)),
        cohort_median_overall_score: Number(baselineOverall.toFixed(2)),
      };
      await env.DB.prepare(
        `INSERT INTO operator_performance_evidence (
          id, brand_key, checkpoint_hours, dimension, feature_key, sample_size, cohort_size,
          medians_json, effect_json, confidence_score, confidence_label, direction, status, evaluator_version
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'active', ?)
        ON CONFLICT(brand_key, checkpoint_hours, dimension, feature_key) DO UPDATE SET
          sample_size = excluded.sample_size,
          cohort_size = excluded.cohort_size,
          medians_json = excluded.medians_json,
          effect_json = excluded.effect_json,
          confidence_score = excluded.confidence_score,
          confidence_label = excluded.confidence_label,
          direction = excluded.direction,
          status = 'active',
          evaluator_version = excluded.evaluator_version,
          updated_at = CURRENT_TIMESTAMP`,
      ).bind(
        crypto.randomUUID(), brandKey, checkpointHours, group.dimension, group.feature,
        sampleSize, rows.length, normalizeOperatorJson(medians, {}), normalizeOperatorJson(effect, {}),
        confidenceScore, confidenceLabel, direction, OPERATOR_PERFORMANCE_EVALUATOR_VERSION,
      ).run();
      const evidence = {
        checkpoint_hours: checkpointHours,
        dimension: group.dimension,
        feature_key: group.feature,
        sample_size: sampleSize,
        cohort_size: rows.length,
        medians,
        effect,
        confidence_score: confidenceScore,
        confidence_label: confidenceLabel,
        direction,
      };
      evidenceRows.push(evidence);
      if (sampleSize >= 3 && direction !== "neutral") {
        const hypothesisText = `At the ${checkpointHours}-hour maturity checkpoint, ${group.dimension}=${group.feature} is associated with ${direction === "positive" ? "stronger" : "weaker"} normalized post performance across ${sampleSize} posts.`;
        await env.DB.prepare(
          `INSERT INTO operator_performance_hypotheses (
            id, brand_key, checkpoint_hours, dimension, feature_key, hypothesis_text,
            direction, sample_size, confidence_score, confidence_label, evidence_json, status, evaluator_version
          ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'active', ?)
          ON CONFLICT(brand_key, checkpoint_hours, dimension, feature_key) DO UPDATE SET
            hypothesis_text = excluded.hypothesis_text,
            direction = excluded.direction,
            sample_size = excluded.sample_size,
            confidence_score = excluded.confidence_score,
            confidence_label = excluded.confidence_label,
            evidence_json = excluded.evidence_json,
            status = 'active',
            evaluator_version = excluded.evaluator_version,
            updated_at = CURRENT_TIMESTAMP`,
        ).bind(
          crypto.randomUUID(), brandKey, checkpointHours, group.dimension, group.feature,
          hypothesisText, direction, sampleSize, confidenceScore, confidenceLabel,
          normalizeOperatorJson(evidence, {}), OPERATOR_PERFORMANCE_EVALUATOR_VERSION,
        ).run();
      }
    }
  }

  const checkpointCounts = Array.from(joinedByCheckpoint.entries())
    .map(([checkpoint, rows]) => ({ checkpoint, sample_size: rows.length }))
    .sort((left, right) => right.checkpoint - left.checkpoint);
  const selectedCheckpoint = checkpointCounts.find((item) => item.sample_size >= 3)
    ?? [...checkpointCounts].sort((left, right) => right.sample_size - left.sample_size || right.checkpoint - left.checkpoint)[0]
    ?? null;
  const selectedEvidence = selectedCheckpoint
    ? evidenceRows.filter((row) => Number(row.checkpoint_hours) === selectedCheckpoint.checkpoint)
    : [];
  const positive = selectedEvidence.filter((row) => row.direction === "positive" && row.confidence_label !== "insufficient")
    .sort((left, right) => Number(right.confidence_score) - Number(left.confidence_score));
  const negative = selectedEvidence.filter((row) => row.direction === "negative" && row.confidence_label !== "insufficient")
    .sort((left, right) => Number(right.confidence_score) - Number(left.confidence_score));
  const recentFingerprints = await env.DB.prepare(
    `SELECT fingerprint_json FROM operator_post_fingerprints WHERE brand_key = ? ORDER BY datetime(updated_at) DESC LIMIT 24`,
  ).bind(brandKey).all<Record<string, unknown>>();
  const fatigueCounts = new Map<string, { dimension: string; feature: string; used: number }>();
  for (const row of recentFingerprints.results ?? []) {
    const fingerprint = operatorRecord(safeParseJsonString(String(row.fingerprint_json ?? "{}")));
    for (const item of operatorFingerprintDimensions(fingerprint)) {
      const key = `${item.dimension}:${item.feature}`;
      const count = fatigueCounts.get(key) ?? { ...item, used: 0 };
      count.used += 1;
      fatigueCounts.set(key, count);
    }
  }
  const recentSampleSize = recentFingerprints.results?.length ?? 0;
  const fatigueRisks = Array.from(fatigueCounts.values())
    .filter((item) => item.used >= 5 && (recentSampleSize === 0 || item.used / recentSampleSize >= 0.25))
    .sort((left, right) => right.used - left.used)
    .slice(0, 10)
    .map((item) => ({ ...item, recent_sample_size: recentSampleSize, fatigue_risk: item.used >= 10 ? "high" : "medium" }));
  const matureSampleSize = selectedCheckpoint?.sample_size ?? 0;
  const allocation = matureSampleSize < 8
    ? { exploitation_percent: 35, improvement_percent: 25, exploration_percent: 40 }
    : matureSampleSize < 20
      ? { exploitation_percent: 50, improvement_percent: 30, exploration_percent: 20 }
      : { exploitation_percent: 60, improvement_percent: 30, exploration_percent: 10 };
  const generatedAt = new Date().toISOString();
  const brief = {
    version: OPERATOR_PERFORMANCE_EVALUATOR_VERSION,
    generated_at: generatedAt,
        checkpoint_hours: selectedCheckpoint?.checkpoint ?? null,
    mature_sample_size: matureSampleSize,
    measurement_policy: {
      checkpoints_hours: [...OPERATOR_PERFORMANCE_MATURITY_CHECKPOINTS],
      final_authoritative_checkpoint_hours: 24,
      collection_scope: "existing_latest_40_full_insights_only",
      targeted_older_post_calls: "forbidden",
      later_metrics: "incidental_archive_context_only",
    },
    follower_attribution_policy: {
      post_level_attribution: "forbidden",
      day_or_period_post_attribution: "forbidden",
      account_level_follower_tracking_only: true,
      reason: "Threads does not expose reliable post-level follower attribution.",
    },
    proven_features: positive.filter((row) => row.confidence_label === "reliable").slice(0, 8),
    directional_features: positive.filter((row) => row.confidence_label === "directional").slice(0, 8),
    weak_features: negative.slice(0, 8),
    fatigue_risks: fatigueRisks,
    experiment_allocation: allocation,
    generation_guidance: [
                  "Use age-matched 6, 12, 18, and 24-hour evidence; treat 24 hours as the final authoritative learning result.",
      "Exploit reliable positive mechanisms, improve one variable at a time, and preserve controlled exploration.",
      "Avoid overused recent features when an equally supported alternative exists.",
      "Do not infer follower conversion from any post, day, batch, or surrounding time period.",
    ],
    source_selection_guidance: {
      prioritize_supported_source_mechanisms: positive.filter((row) => row.dimension === "source_mechanism").slice(0, 5),
      deprioritize_weak_or_fatigued_mechanisms: [
        ...negative.filter((row) => row.dimension === "source_mechanism").slice(0, 5),
        ...fatigueRisks.filter((row) => row.dimension === "source_mechanism").slice(0, 5),
      ],
      confidence_rule: "Account evidence influences selection only when the sample is directional or reliable; otherwise retain broad exploration.",
    },
  };
  await env.DB.prepare(`UPDATE operator_generation_learning_briefs SET active = 0 WHERE brand_key = ? AND active = 1`).bind(brandKey).run();
  const briefId = crypto.randomUUID();
  await env.DB.prepare(
    `INSERT INTO operator_generation_learning_briefs (
      id, brand_key, checkpoint_hours, sample_size, brief_json, active, evaluator_version, generated_at
    ) VALUES (?, ?, ?, ?, ?, 1, ?, ?)`,
  ).bind(
    briefId, brandKey, selectedCheckpoint?.checkpoint ?? null, matureSampleSize,
    normalizeOperatorJson(brief, {}), OPERATOR_PERFORMANCE_EVALUATOR_VERSION, generatedAt,
    ).run();
  const contentFocus = await refreshOperatorContentFocus(env, brandKey);
  return {
    ok: true,
    evaluator_version: OPERATOR_PERFORMANCE_EVALUATOR_VERSION,
    content_focus: contentFocus,
    fingerprinted_posts: fingerprintedPosts,
    maturity_scores_upserted: maturityScores,
    evidence_records: evidenceRows.length,
    active_hypotheses: evidenceRows.filter((row) => Number(row.sample_size) >= 3 && row.direction !== "neutral").length,
    brief_id: briefId,
    checkpoint_hours: selectedCheckpoint?.checkpoint ?? null,
    mature_sample_size: matureSampleSize,
  };
}

async function upsertOperatorContentFocusReview(
  env: Env,
  input: {
    brand_key: GptBrandKey;
    cadence: OperatorContentFocusCadence;
    period_key: string;
    anchor_date: string;
    family_count: number;
    decisions: unknown[];
    generated_at: string;
  },
): Promise<string> {
  const existing = await env.DB.prepare(
    `SELECT id FROM operator_content_focus_reviews
     WHERE brand_key = ? AND cadence = ? AND period_key = ? LIMIT 1`,
  ).bind(input.brand_key, input.cadence, input.period_key).first<{ id: string }>();
  const reviewId = existing?.id ?? crypto.randomUUID();
  await env.DB.prepare(
    `INSERT INTO operator_content_focus_reviews (
      id, brand_key, cadence, period_key, anchor_date, windows_json,
      decisions_json, allocation_json, generated_at, evaluator_version
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(brand_key, cadence, period_key) DO UPDATE SET
      anchor_date = excluded.anchor_date,
      windows_json = excluded.windows_json,
      decisions_json = excluded.decisions_json,
      allocation_json = excluded.allocation_json,
      generated_at = excluded.generated_at,
      evaluator_version = excluded.evaluator_version,
      updated_at = CURRENT_TIMESTAMP`,
  ).bind(
    reviewId, input.brand_key, input.cadence, input.period_key, input.anchor_date,
    normalizeOperatorJson({
      family_count: input.family_count,
      horizons: ["24h", "7d", "30d", "90d", "ytd", "all_time"],
      daily_authority: "near_term_allocation_only",
      weekly_authority: "family_reclassification",
      monthly_authority: "retirement_and_structural_rebalance",
      historical_authority: "context_only",
    }, {}),
    normalizeOperatorJson(input.decisions, []),
    normalizeOperatorJson(OPERATOR_CONTENT_FOCUS_DEFAULT_ALLOCATION, {}),
    input.generated_at, OPERATOR_CONTENT_FOCUS_VERSION,
  ).run();
  return reviewId;
}

async function upsertOperatorContentFocusFamilyState(
  env: Env,
  brandKey: GptBrandKey,
  family: Record<string, unknown>,
  current: Record<string, unknown> | undefined,
  reviewId: string | null,
  decision: OperatorContentFocusDecision | undefined,
): Promise<void> {
  const status = family.status as OperatorContentFocusStatus;
  let weight = Number(family.allocation_weight ?? 0);
  if (weight > 0 && decision?.role === "use_more") weight += 0.2;
  if (weight > 0 && decision?.role === "use_less") weight = Math.max(0.05, weight - 0.3);
  if (weight > 0 && decision?.role === "learn_next") weight += 0.05;
  await env.DB.prepare(
    `INSERT INTO operator_content_focus_family_states (
      id, brand_key, source_card_family_id, source_identity_key, status,
      recommended_status, confidence_score, confidence_label, allocation_weight,
      decision_reason, reuse_directives_json, stop_directives_json,
      horizon_evidence_json, manual_lock, last_review_id
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(brand_key, source_card_family_id) DO UPDATE SET
      source_identity_key = excluded.source_identity_key,
      status = CASE WHEN operator_content_focus_family_states.manual_lock = 1 THEN operator_content_focus_family_states.status ELSE excluded.status END,
      recommended_status = excluded.recommended_status,
      confidence_score = excluded.confidence_score,
      confidence_label = excluded.confidence_label,
      allocation_weight = CASE WHEN operator_content_focus_family_states.manual_lock = 1 THEN operator_content_focus_family_states.allocation_weight ELSE excluded.allocation_weight END,
      decision_reason = excluded.decision_reason,
      reuse_directives_json = excluded.reuse_directives_json,
      stop_directives_json = excluded.stop_directives_json,
      horizon_evidence_json = excluded.horizon_evidence_json,
      last_review_id = excluded.last_review_id,
      updated_at = CURRENT_TIMESTAMP`,
  ).bind(
    current?.id ?? crypto.randomUUID(), brandKey, family.source_card_family_id,
    family.source_identity_key, status, family.recommended_status,
    family.confidence_score, family.confidence_label, weight, family.decision_reason,
    normalizeOperatorJson(family.reuse_directives, {}), normalizeOperatorJson(family.stop_directives, {}),
    normalizeOperatorJson(family.horizons, {}), Number(current?.manual_lock ?? 0), reviewId,
  ).run();
}

async function refreshOperatorContentFocus(
  env: Env,
  brandKey: GptBrandKey,
): Promise<Record<string, unknown>> {
  await ensureOperatorPerformanceEvaluatorTables(env);
  const nowMs = Date.now();
  const anchorDate = operatorLocalDateTimeParts(new Date(nowMs), THREADS_INSIGHTS_TIME_ZONE).date;
  const recentReviews = await env.DB.prepare(
    `SELECT cadence, period_key FROM operator_content_focus_reviews
     WHERE brand_key = ? ORDER BY datetime(generated_at) DESC LIMIT 20`,
  ).bind(brandKey).all<{ cadence: string; period_key: string }>();
  const existingPeriods = new Set((recentReviews.results ?? []).map((row) => `${row.cadence}:${row.period_key}`));
  const cadences: OperatorContentFocusCadence[] = ["daily"];
  for (const cadence of ["weekly", "monthly", "quarterly"] as OperatorContentFocusCadence[]) {
    const periodKey = operatorContentFocusPeriodKey(cadence, anchorDate);
    if (!existingPeriods.has(`${cadence}:${periodKey}`)) cadences.push(cadence);
  }
  const authority: OperatorContentFocusCadence = cadences.includes("quarterly") ? "quarterly"
    : cadences.includes("monthly") ? "monthly"
      : cadences.includes("weekly") ? "weekly" : "daily";
  const built = await buildOperatorContentFocusFamilies(env, brandKey, authority, nowMs);
  const families = built.families;
  const dailyDecisions = buildOperatorContentFocusDailyDecisions(operatorContentFocusDailyCandidates(families));
  const generatedAt = new Date(nowMs).toISOString();
  const reviewIds = new Map<OperatorContentFocusCadence, string>();
  for (const cadence of cadences) {
    const decisions = cadence === "daily" ? dailyDecisions : families.map((family) => ({
      source_card_family_id: family.source_card_family_id,
      status: family.status,
      recommended_status: family.recommended_status,
      confidence_score: family.confidence_score,
      reason: family.decision_reason,
    }));
    const reviewId = await upsertOperatorContentFocusReview(env, {
      brand_key: brandKey,
      cadence,
      period_key: operatorContentFocusPeriodKey(cadence, anchorDate),
      anchor_date: anchorDate,
      family_count: families.length,
      decisions,
      generated_at: generatedAt,
    });
    reviewIds.set(cadence, reviewId);
  }
  const authorityReviewId = reviewIds.get(authority) ?? reviewIds.get("daily") ?? null;
  const decisionByFamily = new Map(dailyDecisions.map((decision) => [decision.source_card_family_id, decision]));
  for (const family of families) {
    const familyId = String(family.source_card_family_id);
    await upsertOperatorContentFocusFamilyState(
      env,
      brandKey,
      family,
      built.current_by_family.get(familyId),
      authorityReviewId,
      decisionByFamily.get(familyId),
    );
  }
  return {
    version: OPERATOR_CONTENT_FOCUS_VERSION,
    anchor_date: anchorDate,
    authority_cadence: authority,
    cadences_generated: cadences,
    family_count: families.length,
    daily_decisions: dailyDecisions,
    allocation: OPERATOR_CONTENT_FOCUS_DEFAULT_ALLOCATION,
  };
}

async function getLatestOperatorContentFocus(
  env: Env,
  brandKey: GptBrandKey,
): Promise<Record<string, unknown>> {
  await ensureOperatorPerformanceEvaluatorTables(env);
  const reviewRows = await env.DB.prepare(
    `SELECT cadence, period_key, anchor_date, decisions_json, allocation_json, generated_at
     FROM operator_content_focus_reviews
     WHERE brand_key = ?
     ORDER BY datetime(generated_at) DESC LIMIT 20`,
  ).bind(brandKey).all<Record<string, unknown>>();
  const latestByCadence = new Map<string, Record<string, unknown>>();
  for (const row of reviewRows.results ?? []) {
    const cadence = String(row.cadence ?? "");
    if (cadence && !latestByCadence.has(cadence)) latestByCadence.set(cadence, row);
  }
  const familyRows = await env.DB.prepare(
    `SELECT source_card_family_id, source_identity_key, status, recommended_status,
            confidence_score, confidence_label, allocation_weight, decision_reason,
            reuse_directives_json, stop_directives_json, horizon_evidence_json,
            manual_lock, updated_at
     FROM operator_content_focus_family_states
     WHERE brand_key = ?
     ORDER BY allocation_weight DESC, confidence_score DESC, updated_at DESC`,
  ).bind(brandKey).all<Record<string, unknown>>();
  const review = (cadence: OperatorContentFocusCadence): Record<string, unknown> | null => {
    const row = latestByCadence.get(cadence);
    return row ? {
      cadence,
      period_key: row.period_key,
      anchor_date: row.anchor_date,
      decisions: safeParseJsonString(String(row.decisions_json ?? "[]")) ?? [],
      allocation: safeParseJsonString(String(row.allocation_json ?? "{}")) ?? {},
      generated_at: row.generated_at,
    } : null;
  };
  return {
    available: familyRows.results !== undefined,
    version: OPERATOR_CONTENT_FOCUS_VERSION,
    reviews: {
      daily: review("daily"),
      weekly: review("weekly"),
      monthly: review("monthly"),
      quarterly: review("quarterly"),
    },
    family_states: (familyRows.results ?? []).map((row) => ({
      source_card_family_id: row.source_card_family_id,
      source_identity_key: row.source_identity_key,
      status: row.status,
      recommended_status: row.recommended_status,
      confidence_score: Number(row.confidence_score ?? 0),
      confidence_label: row.confidence_label,
      allocation_weight: Number(row.allocation_weight ?? 0),
      decision_reason: row.decision_reason,
      reuse_directives: safeParseJsonString(String(row.reuse_directives_json ?? "{}")) ?? {},
      stop_directives: safeParseJsonString(String(row.stop_directives_json ?? "{}")) ?? {},
      horizons: safeParseJsonString(String(row.horizon_evidence_json ?? "{}")) ?? {},
      manual_lock: Number(row.manual_lock ?? 0) === 1,
      updated_at: row.updated_at,
    })),
  };
}

async function getLatestOperatorPerformanceLearning(
  env: Env,
  brandKey: GptBrandKey,
  includePosts = false,
): Promise<Record<string, unknown>> {
  await ensureOperatorPerformanceEvaluatorTables(env);
  const briefRow = await env.DB.prepare(
        `SELECT id, checkpoint_hours, sample_size, brief_json, generated_at
     FROM operator_generation_learning_briefs
     WHERE brand_key = ? AND active = 1 AND evaluator_version = ?
     ORDER BY datetime(generated_at) DESC LIMIT 1`,
  ).bind(brandKey, OPERATOR_PERFORMANCE_EVALUATOR_VERSION).first<Record<string, unknown>>();
  const hypotheses = await env.DB.prepare(
    `SELECT checkpoint_hours, dimension, feature_key, hypothesis_text, direction,
            sample_size, confidence_score, confidence_label, evidence_json, updated_at
          FROM operator_performance_hypotheses
     WHERE brand_key = ? AND status = 'active' AND evaluator_version = ?
     ORDER BY confidence_score DESC, sample_size DESC, updated_at DESC LIMIT 30`,
  ).bind(brandKey, OPERATOR_PERFORMANCE_EVALUATOR_VERSION).all<Record<string, unknown>>();
  const evidence = await env.DB.prepare(
    `SELECT checkpoint_hours, dimension, feature_key, sample_size, cohort_size,
            medians_json, effect_json, confidence_score, confidence_label, direction, updated_at
          FROM operator_performance_evidence
     WHERE brand_key = ? AND status = 'active' AND evaluator_version = ?
     ORDER BY checkpoint_hours DESC, confidence_score DESC, sample_size DESC LIMIT 100`,
  ).bind(brandKey, OPERATOR_PERFORMANCE_EVALUATOR_VERSION).all<Record<string, unknown>>();
  const posts = includePosts
    ? await env.DB.prepare(
      `SELECT s.published_post_id, s.checkpoint_hours, s.post_age_hours, s.metrics_json,
              s.rates_json, s.velocity_json, s.scores_json, s.distribution_state, f.fingerprint_json
       FROM operator_post_performance_scores s
       INNER JOIN operator_post_fingerprints f
         ON f.brand_key = s.brand_key AND f.published_post_id = s.published_post_id
              WHERE s.brand_key = ? AND s.valid_for_learning = 1 AND s.evaluator_version = ?
       ORDER BY s.checkpoint_hours DESC, datetime(s.updated_at) DESC LIMIT 100`,
    ).bind(brandKey, OPERATOR_PERFORMANCE_EVALUATOR_VERSION).all<Record<string, unknown>>()
    : { results: [] as Record<string, unknown>[] };
  const contentFocus = await getLatestOperatorContentFocus(env, brandKey);
  return {
    available: Boolean(briefRow),
    evaluator_version: OPERATOR_PERFORMANCE_EVALUATOR_VERSION,
    content_focus: contentFocus,
    brief_id: briefRow?.id ?? null,
    checkpoint_hours: briefRow?.checkpoint_hours ?? null,
    sample_size: Number(briefRow?.sample_size ?? 0),
    generated_at: briefRow?.generated_at ?? null,
    brief: briefRow ? safeParseJsonString(String(briefRow.brief_json ?? "{}")) ?? {} : null,
    hypotheses: (hypotheses.results ?? []).map((row) => ({
      checkpoint_hours: Number(row.checkpoint_hours),
      dimension: row.dimension,
      feature_key: row.feature_key,
      hypothesis_text: row.hypothesis_text,
      direction: row.direction,
      sample_size: Number(row.sample_size),
      confidence_score: Number(row.confidence_score),
      confidence_label: row.confidence_label,
      evidence: safeParseJsonString(String(row.evidence_json ?? "{}")) ?? {},
      updated_at: row.updated_at,
    })),
    evidence: (evidence.results ?? []).map((row) => ({
      checkpoint_hours: Number(row.checkpoint_hours),
      dimension: row.dimension,
      feature_key: row.feature_key,
      sample_size: Number(row.sample_size),
      cohort_size: Number(row.cohort_size),
      medians: safeParseJsonString(String(row.medians_json ?? "{}")) ?? {},
      effect: safeParseJsonString(String(row.effect_json ?? "{}")) ?? {},
      confidence_score: Number(row.confidence_score),
      confidence_label: row.confidence_label,
      direction: row.direction,
      updated_at: row.updated_at,
    })),
    posts: (posts.results ?? []).map((row) => ({
      published_post_id: row.published_post_id,
      checkpoint_hours: Number(row.checkpoint_hours),
      post_age_hours: Number(row.post_age_hours),
      metrics: safeParseJsonString(String(row.metrics_json ?? "{}")) ?? {},
      rates: safeParseJsonString(String(row.rates_json ?? "{}")) ?? {},
      velocity: safeParseJsonString(String(row.velocity_json ?? "{}")) ?? {},
      scores: safeParseJsonString(String(row.scores_json ?? "{}")) ?? {},
      distribution_state: row.distribution_state,
      fingerprint: safeParseJsonString(String(row.fingerprint_json ?? "{}")) ?? {},
    })),
    follower_attribution_policy: {
      post_level_attribution: "forbidden",
      day_or_period_post_attribution: "forbidden",
      account_level_tracking_only: true,
    },
  };
}

async function appendOperatorMetricSnapshotsForPosts(

  env: Env,
  brandKey: GptBrandKey,
  accountId: string,
  threadsUserId: string,
  posts: CachedThreadsPost[],
  collectionSource: string,
): Promise<{ inserted: number; unchanged: number; anomalous: number; linked: number }> {
  await ensureOperatorWorkflowTables(env);
  await ensureOperatorPostMetricSnapshotsTable(env);
  const capturedAt = new Date().toISOString();
  let inserted = 0;
  let unchanged = 0;
  let anomalous = 0;
  let linked = 0;

  for (const post of posts) {
    if (!post.id) continue;
    const evaluated = evaluateThreadsPostMetricsForLearning(post);
    const metricsJson = normalizeOperatorJson(evaluated.metrics, {});
    const latest = await env.DB.prepare(
      `SELECT metrics_json
       FROM operator_post_metric_snapshots
       WHERE brand_key = ? AND published_post_id = ?
       ORDER BY datetime(captured_at) DESC, datetime(created_at) DESC
       LIMIT 1`,
    ).bind(brandKey, post.id).first<{ metrics_json: string }>();
    if (latest?.metrics_json === metricsJson) {
      unchanged += 1;
      continue;
    }

    const scheduled = await env.DB.prepare(
            `SELECT s.id AS scheduled_post_id, d.id AS draft_id, d.run_id AS generation_run_id,
              d.source_card_id, c.source_selection_id
       FROM scheduled_posts s
       LEFT JOIN gpt_generation_drafts d
         ON d.scheduled_post_id = s.id AND d.account_id = ?
       LEFT JOIN operator_source_cards c
         ON c.id = d.source_card_id AND c.brand_key = ?
       WHERE s.threads_user_id = ? AND s.published_post_id = ?
       ORDER BY s.id DESC
       LIMIT 1`,
    ).bind(accountId, brandKey, threadsUserId, post.id).first<Record<string, unknown>>();
    const fallback = scheduled ? null : await env.DB.prepare(
            `SELECT d.scheduled_post_id, d.id AS draft_id, d.run_id AS generation_run_id,
              d.source_card_id, c.source_selection_id
       FROM gpt_generation_drafts d
       LEFT JOIN operator_source_cards c
         ON c.id = d.source_card_id AND c.brand_key = ?
       WHERE d.account_id = ? AND d.threads_user_id = ? AND d.published_post_id = ?
       ORDER BY datetime(d.updated_at) DESC
       LIMIT 1`,
    ).bind(brandKey, accountId, threadsUserId, post.id).first<Record<string, unknown>>();
    const lineage = scheduled ?? fallback;
    if (lineage) linked += 1;
    if (!evaluated.validForLearning) anomalous += 1;

    await env.DB.prepare(
            `INSERT INTO operator_post_metric_snapshots (
        id, brand_key, published_post_id, scheduled_post_id, draft_id, generation_run_id,
        source_card_id, source_selection_id, metrics_json, captured_at,
        valid_for_learning, anomaly_reason, collection_source
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    ).bind(
      crypto.randomUUID(),
      brandKey,
      post.id,
      lineage?.scheduled_post_id === null || lineage?.scheduled_post_id === undefined ? null : Number(lineage.scheduled_post_id),
            lineage?.draft_id ? String(lineage.draft_id) : null,
      lineage?.generation_run_id ? String(lineage.generation_run_id) : null,
      lineage?.source_card_id ? String(lineage.source_card_id) : null,
      lineage?.source_selection_id ? String(lineage.source_selection_id) : null,
      metricsJson,
      capturedAt,
      evaluated.validForLearning ? 1 : 0,
      evaluated.anomalyReason,
      collectionSource,
    ).run();
    inserted += 1;
  }

  return { inserted, unchanged, anomalous, linked };
}

async function replaceThreadsPostsCache(
  env: Env,
  threadsUserId: string,
  posts: CachedThreadsPost[],
  state: ThreadsPostsCacheStatePayload,
): Promise<void> {
  await ensureThreadsPostsCacheTable(env);
  await ensureThreadsPostsCacheStateTable(env);

  await env.DB.prepare(
    `DELETE FROM threads_post_insights_cache
     WHERE threads_user_id = ?`,
  )
    .bind(threadsUserId)
    .run();

  for (const [index, post] of posts.entries()) {
    await env.DB.prepare(
      `INSERT INTO threads_post_insights_cache (
        threads_user_id,
        post_id,
        post_text,
        post_timestamp,
        post_permalink,
        post_username,
        profile_picture_url,
        views,
        likes,
        replies,
        reposts,
        quotes,
        shares,
        sort_order,
        last_refreshed_at
      )
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)`,
    )
      .bind(
        threadsUserId,
        post.id,
        post.text,
        post.timestamp,
        post.permalink,
        post.username,
        post.profile_picture_url,
        post.views,
        post.likes,
        post.replies,
        post.reposts,
        post.quotes,
        post.shares,
        index,
      )
      .run();
  }

  await env.DB.prepare(
    `INSERT INTO threads_posts_cache_state (
      threads_user_id,
      next_cursor,
      has_more,
      last_refreshed_at
    )
    VALUES (?, ?, ?, CURRENT_TIMESTAMP)
    ON CONFLICT(threads_user_id) DO UPDATE SET
      next_cursor = excluded.next_cursor,
      has_more = excluded.has_more,
      last_refreshed_at = CURRENT_TIMESTAMP`,
  )
    .bind(threadsUserId, state.next_cursor, state.has_more ? 1 : 0)
    .run();
}

async function getFreshThreadsPostsCache(
  env: Env,
  threadsUserId: string,
): Promise<{ posts: CachedThreadsPost[]; nextCursor: string | null; hasMore: boolean } | null> {
  await ensureThreadsPostsCacheTable(env);
  await ensureThreadsPostsCacheStateTable(env);

  const state = await env.DB.prepare(
    `SELECT threads_user_id, next_cursor, has_more, last_refreshed_at
     FROM threads_posts_cache_state
     WHERE threads_user_id = ?
       AND datetime(last_refreshed_at) >= datetime('now', '-${THREADS_INSIGHTS_CACHE_MAX_AGE_HOURS} hours')
     LIMIT 1`,
  )
    .bind(threadsUserId)
    .first<ThreadsPostsCacheStateRow>();

  if (!state) {
    return null;
  }

  const postsResult = await env.DB.prepare(
    `SELECT
       post_id,
       post_text,
       post_timestamp,
       post_permalink,
       post_username,
      profile_picture_url,
      views,
      likes,
      replies,
      reposts,
      quotes,
      shares,
      engagement_total
     FROM threads_post_insights_cache
     WHERE threads_user_id = ?
       AND datetime(last_refreshed_at) >= datetime('now', '-${THREADS_INSIGHTS_CACHE_MAX_AGE_HOURS} hours')
     ORDER BY sort_order ASC`,
  )
    .bind(threadsUserId)
    .all<{
      post_id: string;
      post_text: string | null;
      post_timestamp: string | null;
      post_permalink: string | null;
      post_username: string | null;
      profile_picture_url: string | null;
      views: number | string | null;
      likes: number | string | null;
      replies: number | string | null;
      reposts: number | string | null;
      quotes: number | string | null;
      shares: number | string | null;
      engagement_total: number | string | null;
    }>();

  const posts = (postsResult.results ?? []).map((row) => ({
    id: row.post_id,
    text: row.post_text,
    timestamp: row.post_timestamp,
    permalink: row.post_permalink,
    username: row.post_username,
    profile_picture_url: row.profile_picture_url,
    views: Number(row.views ?? 0),
    likes: Number(row.likes ?? 0),
    replies: Number(row.replies ?? 0),
    reposts: Number(row.reposts ?? 0),
    quotes: Number(row.quotes ?? 0),
    shares: Number(row.shares ?? 0),
    engagement_total: Number(row.engagement_total ?? 0),
  }));

  return {
    posts,
    nextCursor: state.next_cursor ?? null,
    hasMore: state.has_more === 1,
  };
}

async function getThreadsPostsCache(
  env: Env,
  threadsUserId: string,
  options: { allowStale?: boolean } = {},
): Promise<{ posts: CachedThreadsPost[]; nextCursor: string | null; hasMore: boolean } | null> {
  await ensureThreadsPostsCacheTable(env);
  await ensureThreadsPostsCacheStateTable(env);

  const freshnessClause = options.allowStale
    ? ""
    : `AND datetime(last_refreshed_at) >= datetime('now', '-${THREADS_INSIGHTS_CACHE_MAX_AGE_HOURS} hours')`;

  const state = await env.DB.prepare(
    `SELECT threads_user_id, next_cursor, has_more, last_refreshed_at
     FROM threads_posts_cache_state
     WHERE threads_user_id = ?
       ${freshnessClause}
     ORDER BY datetime(last_refreshed_at) DESC
     LIMIT 1`,
  )
    .bind(threadsUserId)
    .first<ThreadsPostsCacheStateRow>();

  if (!state) {
    return null;
  }

  const postsResult = await env.DB.prepare(
    `SELECT
       post_id,
       post_text,
       post_timestamp,
       post_permalink,
       post_username,
       profile_picture_url,
       views,
       likes,
       replies,
       reposts,
       quotes,
       shares,
       engagement_total
     FROM threads_post_insights_cache
     WHERE threads_user_id = ?
       ${freshnessClause}
     ORDER BY sort_order ASC`,
  )
    .bind(threadsUserId)
    .all<{
      post_id: string;
      post_text: string | null;
      post_timestamp: string | null;
      post_permalink: string | null;
      post_username: string | null;
      profile_picture_url: string | null;
      views: number | string | null;
      likes: number | string | null;
      replies: number | string | null;
      reposts: number | string | null;
      quotes: number | string | null;
      shares: number | string | null;
      engagement_total: number | string | null;
    }>();

  const posts = (postsResult.results ?? []).map((row) => ({
    id: row.post_id,
    text: row.post_text,
    timestamp: row.post_timestamp,
    permalink: row.post_permalink,
    username: row.post_username,
    profile_picture_url: row.profile_picture_url,
    views: Number(row.views ?? 0),
    likes: Number(row.likes ?? 0),
    replies: Number(row.replies ?? 0),
    reposts: Number(row.reposts ?? 0),
    quotes: Number(row.quotes ?? 0),
    shares: Number(row.shares ?? 0),
    engagement_total: Number(row.engagement_total ?? 0),
  }));

  return {
    posts,
    nextCursor: state.next_cursor ?? null,
    hasMore: state.has_more === 1,
  };
}

